    'pages.operasional.workflow-developer-harian.item_3' => 'Make sure the environment is ready (<code>.env</code>, DB, cache).',
    'pages.operasional.workflow-developer-harian.item_4' => 'Change Blade/config according to the scope of the task.',
    'pages.operasional.workflow-developer-harian.item_5' => 'Use the automatic route from <code>resources/views/pages</code>.',
    'pages.operasional.workflow-developer-harian.item_6' => 'Check the active state menu on desktop and mobile.',
