    'pages.operasional.workflow-developer-harian.item_9' => 'Helper title validation does not fallback to raw text.',
    'pages.operasional.workflow-developer-harian.lead' => 'The developer\'s daily workflow for the Metronic Laravel project: from setup, development loop, quality gate, to release readiness.',
    'pages.operasional.workflow-developer-harian.note_1' => 'Run clear cache when there are changes to route/config/lang so that verification results are accurate.',
