    'pages.skema.auth-dan-middleware.hero_title' => 'Auth & Middleware Architecture (Security Blueprint)',
    'pages.skema.auth-dan-middleware.hero_lead' => 'Security foundation: user authentication flow, route protection (guest, auth, verified), custom middleware (SetLocale, UpdateUserLastActivity), and User Management integration.',
    'pages.skema.auth-dan-middleware.chip_1' => 'routes/auth.php',
    'pages.skema.auth-dan-middleware.chip_2' => 'auth guard',
    'pages.skema.auth-dan-middleware.chip_3' => 'email verified',
    'pages.skema.auth-dan-middleware.chip_4' => 'signed URL',
    'pages.skema.auth-dan-middleware.chip_5' => 'request throttle',
    'pages.skema.auth-dan-middleware.heading_1' => 'Login Flow & Page Access (Lifecycle)',
    'pages.skema.auth-dan-middleware.heading_2' => 'Auth Route Map & Middleware Mapping',
    'pages.skema.auth-dan-middleware.heading_3' => 'Route Protection Architecture',
    'pages.skema.auth-dan-middleware.heading_4' => 'Custom Middleware: SetLocale & Activity Tracking',
    'pages.skema.auth-dan-middleware.heading_5' => 'Minimum Security & Protection Checklist',
    'pages.skema.auth-dan-middleware.heading_6' => 'Middleware Matrix & Access Levels (Practical)',
    'pages.skema.auth-dan-middleware.heading_7' => 'Team Engineering Standards & Strict Auth Rules',
    'pages.skema.auth-dan-middleware.heading_8' => 'Auth Debugging & Troubleshooting Matrix',
    'pages.skema.auth-dan-middleware.item_1' => 'The 404 fallback route is placed outside the <code>auth</code> middleware to keep error responses consistent for general public users.',
    'pages.skema.auth-dan-middleware.item_2' => 'Ensure all internal and sensitive routes always reside inside <code>auth</code> middleware protection.',
    'pages.skema.auth-dan-middleware.item_3' => 'Validate redirect URLs and guard flow during login/logout to prevent Open Redirect vulnerabilities.',
    'pages.skema.auth-dan-middleware.item_4' => 'Test 3-tier user scenarios: guest, authenticated, and unverified user for each new route.',
    'pages.skema.auth-dan-middleware.item_5' => 'Main <code>/dashboard</code> serves users under <code>auth</code> + <code>verified</code> middleware protection.',
    'pages.skema.auth-dan-middleware.item_6' => 'All automatic routes in <code>routes/menu.php</code> are wrapped by <code>auth</code> middleware.',
    'pages.skema.auth-dan-middleware.item_7' => 'Profile management under <code>routes/web.php</code> is also inside the <code>auth</code> middleware group.',
    'pages.skema.auth-dan-middleware.item_8' => 'For critical feature areas, add <code>verified</code> or additional role authorization middleware as needed.',
    'pages.skema.auth-dan-middleware.item_9' => 'Leverage <code>signed</code> and <code>throttle</code> middleware as seen in email verification and password reset flows.',
    'pages.skema.auth-dan-middleware.lead' => 'Security foundation: user authentication flow, route protection (guest, auth, verified), custom middleware (SetLocale, UpdateUserLastActivity), and User Management integration.',
    'pages.skema.auth-dan-middleware.note_1' => 'Security Impact: Unauthenticated users attempting to open protected pages will be redirected (302 redirect) to <code>/login</code>.',
    'pages.skema.auth-dan-middleware.step_1' => '2. Submit credentials to <code>POST /login</code>.',
    'pages.skema.auth-dan-middleware.step_2' => '3. If successful, auth session is activated, <code>LogUserLogin</code> event listener grants +1 daily reward point, and user is redirected to dashboard.',
    'pages.skema.auth-dan-middleware.step_3' => '4. Protected routes (dashboard/menu pages) can only be accessed if they pass the <code>auth</code> middleware check.',
    'pages.skema.auth-dan-middleware.step_4' => '5. Specific sensitive routes also enforce <code>verified</code> middleware for email verification.',
    'pages.skema.auth-dan-middleware.step_5' => '<strong>Throttling Rule Mandatory:</strong> Sensitive endpoints (login/reset password) must use rate limiting throttle to prevent brute force abuse.',
    'pages.skema.auth-dan-middleware.step_6' => '<strong>Zero Leakage Rule Mandatory:</strong> Do not expose internal authentication exception details in user error messages.',
    'pages.skema.auth-dan-middleware.step_7' => '<strong>3-Tier Testing Rule Mandatory:</strong> Every auth flow change must be tested for guest, verified user, and unverified user.',
    'pages.skema.auth-dan-middleware.step_8' => '1. Guest user accesses <code>/login</code> (defined in <code>routes/auth.php</code>).',
    'pages.skema.auth-dan-middleware.step_9' => '<strong>Route Classification Rule Mandatory:</strong> New routes must be clearly classified: Public vs Auth vs Auth+Verified.',
    'pages.skema.auth-dan-middleware.warn_1' => 'Custom middleware `SetLocale` & `UpdateUserLastActivity` run in the `web` middleware group (`bootstrap/app.php`), executing automatically on every HTTP web request.',
    'pages.skema.cache-dan-deployment.chip_1' => 'performance-focused',
    'pages.skema.cache-dan-deployment.chip_10' => 'Mandatory rollback',
    'pages.skema.cache-dan-deployment.chip_2' => 'stability-first',
    'pages.skema.cache-dan-deployment.chip_3' => 'repeatable release flow',
    'pages.skema.cache-dan-deployment.chip_4' => 'first diagnosis',
    'pages.skema.cache-dan-deployment.chip_5' => 'targeted cache clear',
    'pages.skema.cache-dan-deployment.chip_6' => 'verify after every change',
    'pages.skema.cache-dan-deployment.chip_7' => 'pipeline-driven only',
    'pages.skema.cache-dan-deployment.chip_8' => 'two-party approval',
    'pages.skema.cache-dan-deployment.chip_9' => 'enforced deploy window',
    'pages.skema.cache-dan-deployment.heading_1' => 'Cache & Deployment Purpose',
    'pages.skema.cache-dan-deployment.heading_10' => 'Quick Cache Troubleshooting',
    'pages.skema.cache-dan-deployment.heading_11' => 'Team Standard (Strict) Cache & Deployment',
    'pages.skema.cache-dan-deployment.heading_12' => 'Standard Command Sequence (Production)',
    'pages.skema.cache-dan-deployment.heading_13' => 'Approval Gate Before Migrate',
    'pages.skema.cache-dan-deployment.heading_14' => 'Deploy Time-Window Rules',
    'pages.skema.cache-dan-deployment.heading_15' => 'Release Gate (Pass/Fail)',
    'pages.skema.cache-dan-deployment.heading_2' => 'Relevant Cache Types',
    'pages.skema.cache-dan-deployment.heading_3' => 'Command Cache Strategy (When to Use)',
    'pages.skema.cache-dan-deployment.heading_4' => 'Runbook Deployment (Minimal Risk)',
    'pages.skema.cache-dan-deployment.heading_5' => 'When to Clear Cache',
    'pages.skema.cache-dan-deployment.heading_6' => 'When Don\'t Clear Everything',
    'pages.skema.cache-dan-deployment.heading_7' => 'Pre-Release Checklist',
    'pages.skema.cache-dan-deployment.heading_8' => 'Post-Release Checklist',
    'pages.skema.cache-dan-deployment.heading_9' => 'Rollback Plan (Required)',
    'pages.skema.cache-dan-deployment.item_1' => 'Improve framework startup performance and response time.',
    'pages.skema.cache-dan-deployment.item_10' => 'When an incident is active without a clear hypothesis regarding the cache.',
    'pages.skema.cache-dan-deployment.item_11' => 'During peak traffic, unless mitigation is absolutely necessary.',
    'pages.skema.cache-dan-deployment.item_12' => 'Use a targeted approach first before clearing completely.',
    'pages.skema.cache-dan-deployment.item_13' => '<strong>Config unchanged:</strong> check <code>.env</code> and run <code>config:cache</code> again.',
    'pages.skema.cache-dan-deployment.item_14' => '<strong>Route error after cache:</strong> look for route closure, change to controller action, then recache.',
    'pages.skema.cache-dan-deployment.item_15' => '<strong>Old view still showing:</strong> run <code>view:clear</code> then <code>view:cache</code>.',
    'pages.skema.cache-dan-deployment.item_16' => '<strong>Queue using old code:</strong> run <code>queue:restart</code> and check supervisor status.',
    'pages.skema.cache-dan-deployment.item_17' => 'Migration impact checklist (large table, lock risk, estimated duration).',
    'pages.skema.cache-dan-deployment.item_18' => 'Confirm backup/restore readiness.',
    'pages.skema.cache-dan-deployment.item_19' => 'Confirm application compatibility during schema transition.',
    'pages.skema.cache-dan-deployment.item_2' => 'Reduces the risk of human error during release.',
    'pages.skema.cache-dan-deployment.item_20' => 'PIC release and PIC data sign approval.',
    'pages.skema.cache-dan-deployment.item_21' => 'Regular deployment only during team-agreed operating hours.',
    'pages.skema.cache-dan-deployment.item_22' => 'Avoid deploying during peak business traffic.',
    'pages.skema.cache-dan-deployment.item_23' => 'Freeze windows are applied during critical business events.',
    'pages.skema.cache-dan-deployment.item_24' => 'Emergency deploy outside the mandatory incident status window + IC approval.',
    'pages.skema.cache-dan-deployment.item_3' => 'Keep deployments consistent, repeatable, and easy to rollback.',
    'pages.skema.cache-dan-deployment.item_4' => 'Distinguish when you need to regenerate cache and when you need to completely clear cache.',
    'pages.skema.cache-dan-deployment.item_5' => 'Config changes are not read even though the file has been updated.',
    'pages.skema.cache-dan-deployment.item_6' => 'The new route does not appear or the old route is still in use.',
    'pages.skema.cache-dan-deployment.item_7' => 'The old Blade display still appears after deploy.',
    'pages.skema.cache-dan-deployment.item_8' => 'Anomaly issue after rollback/forward deployment.',
    'pages.skema.cache-dan-deployment.item_9' => 'When the system is stable and there is no indication of cache stale.',
    'pages.skema.cache-dan-deployment.hero_title' => 'Cache & Deployment Architecture (Release Operations Blueprint)',
    'pages.skema.cache-dan-deployment.hero_lead' => 'Config/route/view cache strategy, production deployment runbook, pre & post-release checklists, rollback SOP, stale cache troubleshooting, and release approval gates.',
    'pages.skema.cache-dan-deployment.lead' => '<code>config:cache</code>, <code>route:cache</code>, <code>view:cache</code>, when to clear cache, and checklist release.',
    'pages.skema.cache-dan-deployment.note_1' => 'If using a supervisor/horizon/queue worker, make sure the worker reads the latest code after deploying.',
    'pages.skema.cache-dan-deployment.note_2' => 'If any step fails, the process stops and the release status changes to failed to prevent partial deploy.',
    'pages.skema.cache-dan-deployment.step_1' => '<code>php artisan route:cache</code>: execute if the entire route is cache compatible (no closure).',
    'pages.skema.cache-dan-deployment.step_10' => '3. Monitor the first 10-30 minutes of application logs.',
    'pages.skema.cache-dan-deployment.step_11' => '4. Validate worker/cron running with the latest code.',
    'pages.skema.cache-dan-deployment.step_12' => '5. Send the completed release status to stakeholders.',
    'pages.skema.cache-dan-deployment.step_13' => '<strong>Rule mandatory:</strong> command sequence must follow the official runbook without skipping steps.',
    'pages.skema.cache-dan-deployment.step_14' => '<strong>Required rule:</strong> migration requires gate approval of at least 2 parties (PIC release + PIC data/tech lead).',
    'pages.skema.cache-dan-deployment.step_15' => '<strong>Required rule:</strong> every release must have a documented rollback plan before execution.',
    'pages.skema.cache-dan-deployment.step_16' => '<strong>Required rule:</strong> releases outside the time window are only permitted for emergencies with approval from the incident commander.',
    'pages.skema.cache-dan-deployment.step_17' => '<strong>Required rule:</strong> post-release smoke test and observability check must be completed before the status is â€œdoneâ€.',
    'pages.skema.cache-dan-deployment.step_18' => '<strong>Optional rule:</strong> use canary/blue-green for high-risk features.',
    'pages.skema.cache-dan-deployment.step_19' => 'Gate 2 - Migration: complete approval and successful migration without errors.',
    'pages.skema.cache-dan-deployment.step_2' => '<code>php artisan view:cache</code>: run to speed up first-hit Blade.',
    'pages.skema.cache-dan-deployment.step_20' => 'Gate 3 - Cache: config/route/view cache regenerate successful.',
    'pages.skema.cache-dan-deployment.step_21' => 'Gate 4 - Runtime: worker restart successful and health check green.',
    'pages.skema.cache-dan-deployment.step_22' => 'Gate 5 - Post-check: smoke test critical endpoint passed.',
    'pages.skema.cache-dan-deployment.step_23' => 'If one of the gates fails, rollback according to the runbook.',
    'pages.skema.cache-dan-deployment.step_24' => '<code>php artisan config:cache</code>: run each release after configuration/application update.',
    'pages.skema.cache-dan-deployment.step_25' => '1. Make sure the branch release is frozen and QA validated.',
    'pages.skema.cache-dan-deployment.step_26' => '1. Smoke test login, dashboard, main transactions, and error pages.',
    'pages.skema.cache-dan-deployment.step_27' => '<strong>Rule mandatory:</strong> production deployment only via default pipeline/script, not random manual commands.',
    'pages.skema.cache-dan-deployment.step_28' => 'Gate 1 - Preflight: all dependencies/builds passed.',
    'pages.skema.cache-dan-deployment.step_3' => '<code>php artisan optimize:clear</code>: use only when troubleshooting cache stale or before full regenerate.',
    'pages.skema.cache-dan-deployment.step_4' => 'Safe sequence: clear as necessary -> regenerate cache -> smoke test.',
    'pages.skema.cache-dan-deployment.step_5' => '2. Verify the migration is safe and have a rollback plan.',
    'pages.skema.cache-dan-deployment.step_6' => '3. Verify the route is compatible for <code>route:cache</code>.',
    'pages.skema.cache-dan-deployment.step_7' => '4. Set up a maintenance message/feature flag if necessary.',
    'pages.skema.cache-dan-deployment.step_8' => '5. Define the deploy PIC, verification PIC, and communication PIC.',
    'pages.skema.cache-dan-deployment.step_9' => '2. Monitor metrics: 4xx/5xx error rate, latency, queue backlog.',
    'pages.skema.cache-dan-deployment.warn_1' => 'Impulsively clearing can increase startup load and extend recovery time.',
    'pages.skema.cache-dan-deployment.warn_2' => 'Without gate approval, migration production cannot be executed.',
    'pages.skema.data-layer.chip_1' => 'domain model',
    'pages.skema.data-layer.chip_2' => 'schema evolution',
    'pages.skema.data-layer.chip_3' => 'query discipline',
    'pages.skema.data-layer.chip_4' => 'max 3 eager relations',
    'pages.skema.data-layer.chip_5' => 'max nested depth 2',
    'pages.skema.data-layer.chip_6' => 'mandatory transaction',
    'pages.skema.data-layer.chip_7' => 'no query in loop',
    'pages.skema.data-layer.code_1' => 'Core Domain Relationship Example:',
    'pages.skema.data-layer.heading_1' => 'Data Layer Core Components',
    'pages.skema.data-layer.heading_10' => 'Observability, Debugging, & Query Metrics',
    'pages.skema.data-layer.heading_11' => 'Data Layer Pre-Merge Review Checklist',
    'pages.skema.data-layer.heading_12' => 'Team Engineering Standards & Strict Data Rules',
    'pages.skema.data-layer.heading_13' => 'Mandatory DB Transaction Use-Cases',
    'pages.skema.data-layer.heading_14' => 'Standard Atomic DB Transaction Template',
    'pages.skema.data-layer.heading_15' => 'Strict Pull Request Review Gate (Data Layer)',
    'pages.skema.data-layer.heading_2' => 'End-to-End Data Lifecycle Flow',
    'pages.skema.data-layer.heading_3' => 'Recommended Eloquent Model Structure & Relationships',
    'pages.skema.data-layer.heading_4' => 'Migration Standards & Indexing Strategy',
    'pages.skema.data-layer.heading_5' => 'Migration Schema Example & Index Composition',
    'pages.skema.data-layer.heading_6' => 'Seeder Strategy & Testing Factory Graph',
    'pages.skema.data-layer.heading_7' => 'Optimized Query Patterns & N+1 Prevention',
    'pages.skema.data-layer.heading_8' => 'Safe Query Example (Selective Select + Eager Loading + Pagination)',
    'pages.skema.data-layer.heading_9' => 'Database Transactions & Atomic Data Consistency',
    'pages.skema.data-layer.item_1' => '<code>app/Models/*</code> for Eloquent entities and business domain relationship mappings.',
    'pages.skema.data-layer.item_10' => 'Employ pessimistic/optimistic locking as necessary for race-condition processes (inventory stock, account balances, document sequences).',
    'pages.skema.data-layer.item_11' => '<strong>Transactions & Consistency:</strong> All multi-table write operations must be atomic.',
    'pages.skema.data-layer.item_12' => 'Enable query logging in staging environment to capture slow queries (>100ms) and their triggering endpoints.',
    'pages.skema.data-layer.item_13' => 'Audit migration & seeder completeness during pre-deploy release checklists.',
    'pages.skema.data-layer.item_14' => 'Attach contextual logging (user_id, tenant_id, request_id) whenever data layer exceptions occur.',
    'pages.skema.data-layer.item_15' => '<strong>Order Creation:</strong> Atomically insert order + order items + update inventory stock.',
    'pages.skema.data-layer.item_16' => '<strong>Payment Processing:</strong> Atomically update invoice status, post to accounting ledger, and update order status.',
    'pages.skema.data-layer.item_17' => '<strong>Multi-Stage Approval Workflow:</strong> Approval state changes impacting multiple audit log tables.',
    'pages.skema.data-layer.item_18' => '<strong>Batch Data Import:</strong> Bulk insertion of parent-child records.',
    'pages.skema.data-layer.item_19' => '<code>database/seeders/*</code> and <code>database/factories/*</code> for initial application seeding & unit/feature test graph data.',
    'pages.skema.data-layer.item_2' => '<code>database/migrations/*</code> for database table schema version evolution.',
    'pages.skema.data-layer.item_20' => '<code>app/Providers/AppServiceProvider.php</code> for global database guardrails (e.g. strict mode, lazy loading prevention policies).',
    'pages.skema.data-layer.item_21' => 'If external side effects exist (emails, webhooks, queue jobs), trigger them after transaction commits successfully.',
    'pages.skema.data-layer.item_22' => 'Utilize observability tools (Laravel Telescope / Clockwork / APM) to monitor query execution durations.',
    'pages.skema.data-layer.item_23' => 'Encapsulate reusable query logic inside local scopes (e.g. <code>scopeActive()</code>, <code>scopeForTenant()</code>) for testability and clean code.',
    'pages.skema.data-layer.item_3' => 'Use explicit relationship names reflecting the business domain (e.g. <code>orderItems()</code>, <code>customer()</code>).',
    'pages.skema.data-layer.item_4' => 'Prohibited from placing HTML/Blade presentation logic inside Eloquent Models.',
    'pages.skema.data-layer.item_5' => 'Utilize Factories to construct complex relational data graphs consistently during automated testing.',
    'pages.skema.data-layer.item_6' => '<strong>Seeder & Factory Strategy:</strong> Separate baseline seed data from mock testing graphs.',
    'pages.skema.data-layer.item_7' => 'Keep demo/testing seeders separated so they are never executed in production environments.',
    'pages.skema.data-layer.item_8' => 'Leverage <code>Factory States</code> to simplify test data variation scenarios.',
    'pages.skema.data-layer.item_9' => 'Wrap all multi-table write operations inside <code>DB::transaction()</code> to prevent partial data corruption.',
    'pages.skema.data-layer.lead' => 'Eloquent model architecture, domain relationships, migration & indexing standards, seeder/factory strategy, query optimization (anti N+1 & pagination), atomic DB transactions, and PR gate review.',
    'pages.skema.data-layer.note_1' => 'DB Index Note: Compound indexes must match actual query filter patterns, rather than adding random indexes to every column.',
    'pages.skema.data-layer.step_1' => '2. Query is executed via Model / Local Scope / Query Object.',
    'pages.skema.data-layer.step_10' => 'Extract dynamic filters into local scopes to keep controllers concise, clean, and testable.',
    'pages.skema.data-layer.step_11' => '2. Migration contains relevant indexes and foreign key constraints.',
    'pages.skema.data-layer.step_12' => '3. List queries use minimal column selection (`select`), pagination, and measured eager loading.',
    'pages.skema.data-layer.step_13' => '4. Multi-entity write operations are wrapped inside database transactions (`DB::transaction`).',
    'pages.skema.data-layer.step_14' => '5. Seeders and factories adequately cover local development and automated testing.',
    'pages.skema.data-layer.step_15' => '6. Verified free of N+1 query loops and unbounded heavy database queries.',
    'pages.skema.data-layer.step_16' => '<strong>Mandatory Pagination Rule:</strong> List endpoints must employ pagination (`paginate()`); unbounded data fetches (`all()`, `get()` without limit) are strictly prohibited.',
    'pages.skema.data-layer.step_17' => '<strong>Mandatory Max 3 Eager Relations Rule:</strong> Limit queries to maximum <code>3 eager relations</code> by default (unless technical justification is documented in PR).',
    'pages.skema.data-layer.step_18' => '<strong>Mandatory Max 2 Level Nested Rule:</strong> Limit nested eager loading to maximum <code>2 levels</code> (e.g. `with("orders.items")`) to control query complexity.',
    'pages.skema.data-layer.step_19' => '<strong>Mandatory Atomic Transaction Rule:</strong> Multi-table write operations or consistency-critical processes must run inside <code>DB::transaction()</code>.',
    'pages.skema.data-layer.step_2' => '3. Relationship loading is selectively controlled (selective eager loading).',
    'pages.skema.data-layer.step_20' => '<strong>Mandatory Post-Commit Side Effects Rule:</strong> External side effects (emails, webhooks, queue dispatch) must execute after transaction commits.',
    'pages.skema.data-layer.step_21' => '<strong>Mandatory No Queries in Loops Rule:</strong> Query execution inside loops (for/foreach) is strictly prohibited.',
    'pages.skema.data-layer.step_22' => '<strong>Optional Query Cache Rule:</strong> Employ query caching only for stable read-heavy data backed by explicit invalidation strategies.',
    'pages.skema.data-layer.step_23' => '2. Attach evidence (e.g. query log / profiler output) demonstrating the endpoint is free of N+1 queries.',
    'pages.skema.data-layer.step_24' => '3. If queries exceed 3 eager relations or 2 nested levels, provide explicit technical justification in PR.',
    'pages.skema.data-layer.step_25' => '4. For financial or inventory processes, explicitly document transaction boundaries and concurrency control strategies.',
    'pages.skema.data-layer.step_26' => '5. Ensure migration rollback is tested and executes safely prior to merging.',
    'pages.skema.data-layer.step_27' => '1. Incoming request &rarr; Controller / Use-Case validates input parameters.',
    'pages.skema.data-layer.step_28' => '1. Document query performance impact and new database indexes in the PR description.',
    'pages.skema.data-layer.step_29' => 'Migrations must be idempotent and traceable (one schema evolution per migration file).',
    'pages.skema.data-layer.step_3' => '4. Data is mapped into DTO / API Resource / View model.',
    'pages.skema.data-layer.step_30' => 'Use explicit <code>select()</code> clauses to retrieve only required columns on list endpoints.',
    'pages.skema.data-layer.step_31' => '1. Eloquent Models and relationships accurately reflect the business domain.',
    'pages.skema.data-layer.step_32' => '<strong>Mandatory Index Rule:</strong> Columns used in filters (`where`), sorting (`orderBy`), search (`like`), and foreign keys must possess appropriate database indexes.',
    'pages.skema.data-layer.step_4' => '5. Critical write operations are encapsulated within atomic database transactions.',
    'pages.skema.data-layer.step_5' => 'Add indexes when creating columns frequently used in filtering, sorting, or joining.',
    'pages.skema.data-layer.step_6' => 'Utilize Foreign Key Constraints to guarantee data integrity (including appropriate `onDelete` actions).',
    'pages.skema.data-layer.step_7' => 'Isolate high-risk schema modifications (renaming or dropping large columns) into dedicated migrations.',
    'pages.skema.data-layer.step_8' => 'Utilize <code>with()</code> or <code>withCount()</code> to eliminate N+1 query issues on list and detail endpoints.',
    'pages.skema.data-layer.step_9' => 'Employ pagination for large datasets; avoid loading entire table rows into memory.',
    'pages.skema.data-layer.warn_1' => 'N+1 Anti-Pattern Warning: Avoid executing queries inside loops. If additional queries per item are detected, refactor immediately with Eager Loading (`with()`).',
    'pages.skema.data-layer.warn_2' => 'Data Consistency Warning: If a single use-case modifies more than one primary table, it must be wrapped inside `DB::transaction()`.',
    'pages.skema.error-handling-dan-fallback.hero_title' => 'Error Handling & Fallback Architecture (Error Architecture Blueprint)',
    'pages.skema.error-handling-dan-fallback.hero_lead' => 'Exception handling architecture, global 404 fallback, API vs Web response standards, log sensitive data masking, incident SOP, and severity matrix.',
    'pages.skema.error-handling-dan-fallback.chip_1' => 'stability-oriented',
    'pages.skema.error-handling-dan-fallback.chip_2' => 'security-centered',
    'pages.skema.error-handling-dan-fallback.chip_3' => 'full traceability',
    'pages.skema.error-handling-dan-fallback.chip_4' => 'single error-response contract',
    'pages.skema.error-handling-dan-fallback.chip_5' => 'no sensitive data in logs',
    'pages.skema.error-handling-dan-fallback.chip_6' => 'postmortem is mandatory',
    'pages.skema.error-handling-dan-fallback.heading_1' => 'Purpose of Error Handling',
    'pages.skema.error-handling-dan-fallback.heading_10' => 'Security Guardrail Rules',
    'pages.skema.error-handling-dan-fallback.heading_11' => 'Retry and Idempotency',
    'pages.skema.error-handling-dan-fallback.heading_12' => 'SOP Incident Error (Concise)',
    'pages.skema.error-handling-dan-fallback.heading_13' => 'Error Handling Review Checklist (Pre-Release)',
    'pages.skema.error-handling-dan-fallback.heading_14' => 'Team Standard (Strict) Error Handling',
    'pages.skema.error-handling-dan-fallback.heading_15' => 'Operational Severity Matrix',
    'pages.skema.error-handling-dan-fallback.heading_16' => 'Standard Postmortem Format (Template)',
    'pages.skema.error-handling-dan-fallback.heading_2' => 'Current Fallbacks in the Project',
    'pages.skema.error-handling-dan-fallback.heading_3' => 'Map Errors to Handle',
    'pages.skema.error-handling-dan-fallback.heading_4' => 'Strategy Mapping Exception -> Response',
    'pages.skema.error-handling-dan-fallback.heading_5' => 'Web Response Standards vs API',
    'pages.skema.error-handling-dan-fallback.heading_6' => 'Example of an API Error Contract (Recommendation)',
    'pages.skema.error-handling-dan-fallback.heading_7' => 'Minimum Logging & Context',
    'pages.skema.error-handling-dan-fallback.heading_8' => 'Redaction of Messages to Users',
    'pages.skema.error-handling-dan-fallback.heading_9' => 'Custom Error Page Templates',
    'pages.skema.error-handling-dan-fallback.item_1' => 'Keep the application providing safe, clear and actionable responses.',
    'pages.skema.error-handling-dan-fallback.item_10' => '<code>user_id</code> (if any), tenant/account id (if multi-tenant).',
    'pages.skema.error-handling-dan-fallback.item_11' => 'Log <code>request_id</code>, URL, HTTP method, and status code.',
    'pages.skema.error-handling-dan-fallback.item_12' => '<code>user_id</code> (if any), tenant/account id (if multi-tenant).',
    'pages.skema.error-handling-dan-fallback.item_13' => 'Security guardrail checklist',
    'pages.skema.error-handling-dan-fallback.item_14' => 'Masking sensitive data in the log (token, secret, password, card number).',
    'pages.skema.error-handling-dan-fallback.item_15' => 'Make sure <code>APP_DEBUG=false</code> in production.',
    'pages.skema.error-handling-dan-fallback.item_16' => 'Masking sensitive data in the log (token, secret, password, card number).',
    'pages.skema.error-handling-dan-fallback.item_17' => 'Retry and idempotency policy',
    'pages.skema.error-handling-dan-fallback.item_18' => 'Critical operations (payments/orders) require idempotency keys to avoid duplication.',
    'pages.skema.error-handling-dan-fallback.item_19' => 'Non-critical operations can be directed to retry with backoff.',
    'pages.skema.error-handling-dan-fallback.item_2' => 'Separating known errors (expected) vs system errors (unexpected).',
    'pages.skema.error-handling-dan-fallback.item_20' => 'Critical operations (payments/orders) require idempotency keys to avoid duplication.',
    'pages.skema.error-handling-dan-fallback.item_3' => 'Ensure the user experience remains good even if failure occurs.',
    'pages.skema.error-handling-dan-fallback.item_4' => 'Provides observability traces for fast investigation (log, context, request id).',
    'pages.skema.error-handling-dan-fallback.item_5' => 'Web Response Standards vs API',
    'pages.skema.error-handling-dan-fallback.item_6' => '<strong>API:</strong> return consistent structured JSON (<code>code</code>, <code>message</code>, <code>details</code>, <code>request_id</code>).',
    'pages.skema.error-handling-dan-fallback.item_7' => '<strong>Web:</strong> display a custom error page (403/404/419/500) with a CTA back to the safe page.',
    'pages.skema.error-handling-dan-fallback.item_8' => '<strong>API:</strong> return consistent structured JSON (<code>code</code>, <code>message</code>, <code>details</code>, <code>request_id</code>).',
    'pages.skema.error-handling-dan-fallback.item_9' => 'Minimum Logging & Context',
    'pages.skema.error-handling-dan-fallback.lead' => 'Current 404 fallback, exception handling, and custom error pages.',
    'pages.skema.error-handling-dan-fallback.note_1' => 'Key principles: users get actionable messages, teams get enough technical logs for investigations.',
    'pages.skema.error-handling-dan-fallback.note_2' => 'Severity is determined by the business impact and extent of affected users, not just the type of exception.',
    'pages.skema.error-handling-dan-fallback.step_1' => 'The fallback is outside the auth middleware, so it can still appear for users who have not logged in.',
    'pages.skema.error-handling-dan-fallback.step_10' => '2. Triage: identify the most affected routes/services and business severity.',
    'pages.skema.error-handling-dan-fallback.step_11' => '3. Quick mitigation: rollback, feature flag off, or degrade mode.',
    'pages.skema.error-handling-dan-fallback.step_12' => '4. Permanent fix: root-cause fix + regression test.',
    'pages.skema.error-handling-dan-fallback.step_13' => '5. Postmortem: documentation of timeline, impact, action items, owner, and due date.',
    'pages.skema.error-handling-dan-fallback.step_14' => '2. The fallback route works and does not swallow application exceptions that need to be fixed.',
    'pages.skema.error-handling-dan-fallback.step_15' => '3. All API endpoints return a consistent JSON error format.',
    'pages.skema.error-handling-dan-fallback.step_16' => '4. The error log contains minimum context without leaking sensitive data.',
    'pages.skema.error-handling-dan-fallback.step_17' => '5. APP_DEBUG production is confirmed to be disabled.',
    'pages.skema.error-handling-dan-fallback.step_18' => '6. Timeout/dependency down scenarios are tested at least once before release.',
    'pages.skema.error-handling-dan-fallback.step_19' => '<strong>Rule mandatory:</strong> 5xx response to client must be generic; technical details only in internal logs.',
    'pages.skema.error-handling-dan-fallback.step_2' => 'All URLs that do not match route will fall into this fallback.',
    'pages.skema.error-handling-dan-fallback.step_20' => '<strong>Rule mandatory:</strong> each error log must have <code>request_id</code>, route, method, status code, and user context (if any).',
    'pages.skema.error-handling-dan-fallback.step_21' => '<strong>Rule mandatory:</strong> there must be no sensitive data in the log (passwords, tokens, secrets, critical PII).',
    'pages.skema.error-handling-dan-fallback.step_22' => '<strong>Rule mandatory:</strong> business exception mapping must be explicit (e.g. conflict -> 409, validation -> 422).',
    'pages.skema.error-handling-dan-fallback.step_23' => '<strong>Required rule:</strong> fallback must not be used to cover bug 500.',
    'pages.skema.error-handling-dan-fallback.step_24' => '<strong>Mandatory rule:</strong> every Sev-1/Sev-2 incident must postmortem a maximum of 2x24 hours.',
    'pages.skema.error-handling-dan-fallback.step_25' => '<strong>Optional rule:</strong> critical endpoint adds idempotency key and scalable retry policy.',
    'pages.skema.error-handling-dan-fallback.step_26' => 'The fallback route leads to the page <code>pages.pages.authentication.general.error-404</code>.',
    'pages.skema.error-handling-dan-fallback.step_27' => 'Validation exception -> response 422 + field-level message.',
    'pages.skema.error-handling-dan-fallback.step_28' => 'Redaction of Messages to Users',
    'pages.skema.error-handling-dan-fallback.step_29' => '1. Detection & Alert: receive error notification from APM, logs, or user reports.',
    'pages.skema.error-handling-dan-fallback.step_3' => 'Use fallback for route not found cases, not to hide application exceptions.',
    'pages.skema.error-handling-dan-fallback.step_30' => '1. Business and system exception mapping is complete and verified.',
    'pages.skema.error-handling-dan-fallback.step_31' => 'Team Standard (Strict) Error Handling',
    'pages.skema.error-handling-dan-fallback.step_4' => 'Exception authorization -> 403 with secure message (no sensitive details).',
    'pages.skema.error-handling-dan-fallback.step_5' => 'Exception domain (eg insufficient stock) -> 409/422 according to context.',
    'pages.skema.error-handling-dan-fallback.step_6' => 'Unknown system exception -> 500 generic + complete log.',
    'pages.skema.error-handling-dan-fallback.step_7' => 'Provide further steps: retry, refresh, re-login, or contact support.',
    'pages.skema.error-handling-dan-fallback.step_8' => 'Use a consistent tone between error pages.',
    'pages.skema.error-handling-dan-fallback.step_9' => 'If necessary, display <code>request_id</code> so support can easily browse the logs.',
    'pages.skema.error-handling-dan-fallback.warn_1' => 'Avoid changing the error response format between endpoints randomly. Contract consistency is important for frontend/mobile clients.',
    'pages.skema.error-handling-dan-fallback.warn_2' => 'Postmortems focus on improving systems, not blaming individuals.',
    'pages.skema.header-menu.hero_title' => 'Header Navigation & Mega Menu Architecture (Header Blueprint)',
    'pages.skema.header-menu.hero_lead' => 'Horizontal top-bar menu orchestration in Metronic: 5 distinct UI patterns (Mega Card, Mega Tabbed, Recursive Dropdown, Mega Column, & Compact Hybrid), Blade partial integration, and mobile drawer wrapper.',
    'pages.skema.header-menu.chip_1' => 'Dashboards = Mega Card',
    'pages.skema.header-menu.chip_2' => 'Pages = Mega Tabbed',
    'pages.skema.header-menu.chip_3' => 'Apps = Recursive Dropdown',
    'pages.skema.header-menu.chip_4' => 'Layouts = Mega Column',
    'pages.skema.header-menu.chip_5' => 'Help = Compact Hybrid',
    'pages.skema.header-menu.heading_1' => 'Header Menu Main Orchestration Map',
    'pages.skema.header-menu.heading_10' => 'Header Menu Debugging & Troubleshooting Matrix',
    'pages.skema.header-menu.heading_2' => '5 Distinct Header Submenu UI Patterns',
    'pages.skema.header-menu.heading_3' => '1. Dashboards: Mega Menu Card Pattern',
    'pages.skema.header-menu.heading_4' => '2. Pages: Mega Menu Tabbed Pane Pattern',
    'pages.skema.header-menu.heading_5' => '3. Apps: Recursive Dropdown (Flyout) Pattern',
    'pages.skema.header-menu.heading_6' => '4. Layouts: Mega Menu Grid Column & Builder',
    'pages.skema.header-menu.heading_7' => '5. Help: Compact Hybrid Icon List Pattern',
    'pages.skema.header-menu.heading_8' => 'Pattern Selection Matrix: Mega Menu vs Standard Dropdown',
    'pages.skema.header-menu.heading_9' => 'Team Engineering Standards & Strict Header Rules',
    'pages.skema.header-menu.item_1' => '<strong>Mobile Drawer Mode:</strong> Header automatically transforms into a slide-in navigation drawer using Metronic <code>data-kt-drawer</code> attributes on mobile viewports.',
    'pages.skema.header-menu.item_10' => 'Each internal tab renders a dedicated partial (e.g. <code>__pages-user-profile.blade.php</code>) inside responsive containers.',
    'pages.skema.header-menu.item_11' => 'Renderer Partial: <code>resources/views/layouts/partials/header/_menu/__pages.blade.php</code>.',
    'pages.skema.header-menu.item_12' => 'Config Data Source: <code>config/header/_header_apps.php</code>.',
    'pages.skema.header-menu.item_13' => 'Application menu structure utilizes flyout recursive dropdowns supporting unlimited nested levels.',
    'pages.skema.header-menu.item_14' => 'Level-1 submenus default to flyout; deeper nested levels are controlled via <code>\'dropdown\' => true</code>.',
    'pages.skema.header-menu.item_15' => 'Renderer Partial: <code>resources/views/layouts/partials/header/_menu/__apps.blade.php</code>.',
    'pages.skema.header-menu.item_16' => 'Renderer Partial: <code>resources/views/layouts/partials/header/_menu/__layouts.blade.php</code>.',
    'pages.skema.header-menu.item_17' => 'Organizes menu items into multi-column grid layouts accompanied by visual layout previews and promo illustrations.',
    'pages.skema.header-menu.item_18' => 'Features dedicated "Layout Builder" promotional card for instant visual theme customization.',
    'pages.skema.header-menu.item_19' => 'Config Data Source: <code>config/header/_header_layouts.php</code>.',
    'pages.skema.header-menu.item_2' => 'Top-level active state is calculated dynamically from child routes using <code>request()->routeIs(...)</code> checks.',
    'pages.skema.header-menu.item_20' => 'Config Data Source: <code>config/header/_header_help.php</code>.',
    'pages.skema.header-menu.item_21' => 'Displays compact icon list of help documents equipped with status badges and external link handling.',
    'pages.skema.header-menu.item_22' => 'External links automatically receive <code>target="_blank"</code> attribute for security and smooth UX.',
    'pages.skema.header-menu.item_23' => 'Renderer Partial: <code>resources/views/layouts/partials/header/_menu/__help.blade.php</code>.',
    'pages.skema.header-menu.item_24' => 'Primary Entry Point: <code>resources/views/layouts/partials/header/_menu/_menu.blade.php</code>.',
    'pages.skema.header-menu.item_25' => 'Top-Level Interaction Trigger: <code>data-kt-menu-trigger="{default:\'click\', lg:\'hover\'}"</code>.',
    'pages.skema.header-menu.item_26' => 'Adaptive Pane Width: Employs responsive utility classes such as <code>w-lg-1000px</code>, <code>w-lg-600px</code>, and <code>w-lg-500px</code>.',
    'pages.skema.header-menu.item_27' => '<strong>Submenu Not Opening / Expanding:</strong> Verify <code>data-kt-menu-trigger</code> attribute and HTML <code>menu-sub</code> container elements.',
    'pages.skema.header-menu.item_28' => '<strong>Tab Content Pages Not Switching:</strong> Check Bootstrap tab target <code>id</code> match and initial <code>active</code> nav-link state.',
    'pages.skema.header-menu.item_29' => '<strong>Dropdown Misaligned / Off-Screen:</strong> Inspect <code>data-kt-menu-placement</code> attribute and adjust responsive width bounds.',
    'pages.skema.header-menu.item_3' => 'Renderer Partial: <code>resources/views/layouts/partials/header/_menu/__dashboards.blade.php</code>.',
    'pages.skema.header-menu.item_30' => '<strong>Help Link Inactive / Plain Text:</strong> Check internal Laravel route names and ensure <code>menu.*</code> key is in lang files.',
    'pages.skema.header-menu.item_4' => 'Splits mega menu pane into 2 distinct sections: Visual promo card on left and quick access link list on right.',
    'pages.skema.header-menu.item_5' => 'Right Area: Renders "More Dashboards" list retrieved from <code>header_dashboard_other</code> array.',
    'pages.skema.header-menu.item_6' => 'Config Data Source: <code>config/header/_header_dashboards.php</code>.',
    'pages.skema.header-menu.item_7' => 'Left Area: Renders primary visual dashboard card from <code>header_dashboard_card</code> array.',
    'pages.skema.header-menu.item_8' => 'Config Data Source: <code>config/header/_header_pages.php</code>.',
    'pages.skema.header-menu.item_9' => 'Employs internal tabbed navigation (User Profile, Account, Authentication, Corporate) to categorize large page groups.',
    'pages.skema.header-menu.lead' => 'Horizontal top-bar menu orchestration in Metronic: 5 distinct UI patterns (Mega Card, Mega Tabbed, Recursive Dropdown, Mega Column, & Compact Hybrid), Blade partial integration, and mobile drawer wrapper.',
    'pages.skema.header-menu.note_1' => 'Single top navigation bar orchestrating 5 distinct submenu UI characteristics. Enables maximum UX adaptability per module domain.',
    'pages.skema.header-menu.note_2' => 'Team Best Practice: Determine exact UI pattern (Mega Menu vs Standard Dropdown) prior to writing config arrays and partial renderers to maintain clean architecture.',
    'pages.skema.header-menu.step_1' => '<strong>Standard Dropdown (Flyout):</strong> Ideal for concise link lists with shallow nested hierarchy.',
    'pages.skema.header-menu.step_2' => 'Testing is mandatory for both Desktop mode (Hover interaction) and Mobile mode (Click Drawer interaction).',
    'pages.skema.header-menu.step_3' => '<strong>Domain Isolation Rule Mandatory:</strong> Header configs and partial renderers must remain isolated per domain (avoid mixing cross-domain logic).',
    'pages.skema.header-menu.step_4' => '<strong>Active State Validation Rule Mandatory:</strong> Top-level active states must be validated for both desktop hover and mobile click behaviors.',
    'pages.skema.header-menu.step_5' => '<strong>External Link Safety Rule Mandatory:</strong> External links must explicitly declare <code>target="_blank"</code> and maintain UX security.',
    'pages.skema.header-menu.step_6' => '<strong>Mega Menu (Card/Tab/Column):</strong> Ideal for high-density content, rich visual categorization, and Call-to-Action (CTA) elements.',
    'pages.skema.header-menu.step_7' => '<strong>Pattern Clarity Rule Mandatory:</strong> New top-level menus must define their UI pattern (Mega Card, Tab, Column, or Dropdown) explicitly before implementation.',
    'pages.skema.i18n-lanjutan.chip_1' => 'stable translation keys',
    'pages.skema.i18n-lanjutan.chip_2' => 'namespace domain',
    'pages.skema.i18n-lanjutan.chip_3' => 'zero hardcoded UI strings',
    'pages.skema.i18n-lanjutan.chip_4' => 'EN/ID key parity',
    'pages.skema.i18n-lanjutan.chip_5' => 'no untranslated keys',
    'pages.skema.i18n-lanjutan.chip_6' => 'domain-reviewed terminology',
    'pages.skema.i18n-lanjutan.heading_1' => 'Key Translation Standards',
    'pages.skema.i18n-lanjutan.heading_10' => 'i18n Team Standard (Strict).',
    'pages.skema.i18n-lanjutan.heading_2' => 'Current i18n Architecture',
    'pages.skema.i18n-lanjutan.heading_3' => 'File Schema and Translation Domain',
    'pages.skema.i18n-lanjutan.heading_4' => 'Key Naming Convention (Strict)',
    'pages.skema.i18n-lanjutan.heading_5' => 'Workflow Add New Language (End-to-End)',
    'pages.skema.i18n-lanjutan.heading_6' => 'Examples of Translational Governance',
    'pages.skema.i18n-lanjutan.heading_7' => 'Fallback Resolution Strategy',
    'pages.skema.i18n-lanjutan.heading_8' => 'i18n QA Checklist',
    'pages.skema.i18n-lanjutan.heading_9' => 'General Risks & Mitigation',
    'pages.skema.i18n-lanjutan.item_1' => 'Use a consistent namespace, for example <code>menu.*</code>, <code>auth.*</code>, <code>pages.*</code>.',
    'pages.skema.i18n-lanjutan.item_10' => 'If the key does not exist in the active locale, fallback to the default locale.',
    'pages.skema.i18n-lanjutan.item_11' => 'If it\'s still not there, display a safe fallback (original title/controlled placeholder).',
    'pages.skema.i18n-lanjutan.item_12' => 'Note missing keys in the QA log so they can be closed before release.',
    'pages.skema.i18n-lanjutan.item_13' => '<strong>Missing key:</strong> create cross-locale key audit script before merge.',
    'pages.skema.i18n-lanjutan.item_14' => '<strong>Inconsistent terms:</strong> use team glossary per business domain.',
    'pages.skema.i18n-lanjutan.item_15' => '<strong>UI broke due to long string:</strong> test responsive EN/ID (and new locale) on mobile+desktop.',
    'pages.skema.i18n-lanjutan.item_16' => '<strong>Mixed languages:</strong> prohibit hardcoded text on reusable components.',
    'pages.skema.i18n-lanjutan.item_17' => '<strong>Incorrect pluralization:</strong> use the framework\'s built-in plural format for the corresponding language.',
    'pages.skema.i18n-lanjutan.item_2' => 'Avoid hardcoded text on Blade for user-facing text.',
    'pages.skema.i18n-lanjutan.item_3' => 'Keep key stable; change the translation value without changing the key if possible.',
    'pages.skema.i18n-lanjutan.item_4' => 'Use lowercase + underscore: <code>menu.skema_cache_and_deployment</code>.',
    'pages.skema.i18n-lanjutan.item_5' => 'Key names must be descriptive, avoid ambiguous abbreviations.',
    'pages.skema.i18n-lanjutan.item_6' => 'One key for one meaning; do not reuse keys for different contexts.',
    'pages.skema.i18n-lanjutan.item_7' => 'If the string needs variables, use consistent placeholders (e.g. <code>:name</code>, <code>:count</code>).',
    'pages.skema.i18n-lanjutan.item_8' => 'Avoid UI position-based keys (e.g. <code>title_1</code>, <code>label_left</code>).',
    'pages.skema.i18n-lanjutan.item_9' => 'Define the default global locale (e.g. <code>en</code> or <code>id</code>).',
    'pages.skema.i18n-lanjutan.hero_title' => 'Advanced i18n & Localization Architecture (Advanced i18n Blueprint)',
    'pages.skema.i18n-lanjutan.hero_lead' => 'Translation key governance standards, domain namespacing, fallback handling, end-to-end locale onboarding, and i18n QA checklists.',
    'pages.skema.i18n-lanjutan.lead' => 'Naming key standards, translation governance, and end-to-end process for adding new languages.',
    'pages.skema.i18n-lanjutan.note_1' => 'Separate translation domains for easier change review and fewer merge conflicts.',
    'pages.skema.i18n-lanjutan.step_1' => 'The menu label is resolved from the key <code>menu.*</code> based on the config title.',
    'pages.skema.i18n-lanjutan.step_10' => '3. Check validation messages, flash messages, and error pages.',
    'pages.skema.i18n-lanjutan.step_11' => '4. Check text with placeholders/pluralization.',
    'pages.skema.i18n-lanjutan.step_12' => '5. Check layout overflow for longer strings.',
    'pages.skema.i18n-lanjutan.step_13' => '<strong>Rule required:</strong> PRs that change menu/config must include the corresponding translation key update.',
    'pages.skema.i18n-lanjutan.step_14' => '<strong>Required rule:</strong> must not merge if audit shows missing key in mandatory locale.',
    'pages.skema.i18n-lanjutan.step_15' => '<strong>Required rule:</strong> changes to main domain terminology must be approved by the product/domain owner.',
    'pages.skema.i18n-lanjutan.step_16' => '<strong>Optional rule:</strong> maintain glossary per domain for consistent tone across pages.',
    'pages.skema.i18n-lanjutan.step_17' => 'The locale is stored in the session via the language switch route.',
    'pages.skema.i18n-lanjutan.step_18' => '1. Create a new locale folder: <code>lang/{locale}</code>.',
    'pages.skema.i18n-lanjutan.step_19' => '1. Switch locale from the UI and make sure it persists between pages.',
    'pages.skema.i18n-lanjutan.step_2' => 'If the key does not exist, the system falls back to the original text of the menu title.',
    'pages.skema.i18n-lanjutan.step_20' => '<strong>Rule is mandatory:</strong> all new keys must be added at least in <code>en</code> and <code>id</code>.',
    'pages.skema.i18n-lanjutan.step_3' => 'The main translation sources are currently at <code>lang/en/menu.php</code> and <code>lang/id/menu.php</code>.',
    'pages.skema.i18n-lanjutan.step_4' => '2. Duplicate the baseline file from the default language.',
    'pages.skema.i18n-lanjutan.step_5' => '3. Translate per domain + review glossary of terms.',
    'pages.skema.i18n-lanjutan.step_6' => '4. Register the locale to route switch language and UI options.',
    'pages.skema.i18n-lanjutan.step_7' => '5. Test all menus, auth, validation, and critical pages.',
    'pages.skema.i18n-lanjutan.step_8' => '6. Check for lost fallback keys before release.',
    'pages.skema.i18n-lanjutan.warn_1' => 'Renaming translation keys without a usage audit can cause silent fallbacks and UI inconsistencies.',
    'pages.skema.komponen-blade-partial.hero_title' => 'Blade Components & Partials Architecture (Blueprint)',
    'pages.skema.komponen-blade-partial.hero_lead' => 'Comprehensive conventions for @@extends, @@include, @@component, and <x-...> components, plus a decision matrix on when to use Partials vs Blade Components.',
    'pages.skema.komponen-blade-partial.chip_1' => 'Layout Inheritance: @@extends',
    'pages.skema.komponen-blade-partial.chip_2' => 'Static Partial: @@include',
    'pages.skema.komponen-blade-partial.chip_3' => 'Component Contract: <x-...>',
    'pages.skema.komponen-blade-partial.chip_4' => 'Maximum 7 Props',
    'pages.skema.komponen-blade-partial.chip_5' => 'Maximum 2 Named Slots',
    'pages.skema.komponen-blade-partial.chip_6' => 'Zero DB Query in Partial',
    'pages.skema.komponen-blade-partial.heading_1' => '4 Primary Blade Directive Patterns',
    'pages.skema.komponen-blade-partial.heading_10' => 'Boilerplate Component Stat Card',
    'pages.skema.komponen-blade-partial.heading_11' => 'Component Usage Example in Blade View',
    'pages.skema.komponen-blade-partial.heading_12' => 'Component Debugging & Troubleshooting Matrix',
    'pages.skema.komponen-blade-partial.heading_2' => 'Decision Matrix: Partial vs Blade Component',
    'pages.skema.komponen-blade-partial.heading_3' => 'Recommended Component Folder Architecture',
    'pages.skema.komponen-blade-partial.heading_4' => 'Implementation Example: Simple Partial',
    'pages.skema.komponen-blade-partial.heading_5' => 'Implementation Example: Reusable Blade Component',
    'pages.skema.komponen-blade-partial.heading_6' => 'File & Prop Naming Conventions',
    'pages.skema.komponen-blade-partial.heading_7' => 'Anti-Patterns & Common Mistakes to Avoid',
    'pages.skema.komponen-blade-partial.heading_8' => 'Checklist When Creating New UI Elements',
    'pages.skema.komponen-blade-partial.heading_9' => 'Team Engineering Standards & Strict Rules',
    'pages.skema.komponen-blade-partial.item_1' => '<code>@@extends(\'layouts.index\')</code>: To inherit the main application layout wrapper.',
    'pages.skema.komponen-blade-partial.item_10' => 'Use clear domain prop names (<code>title</code>, <code>badge</code>, <code>isActive</code>) and avoid ambiguous generic names.',
    'pages.skema.komponen-blade-partial.item_11' => '<strong>God Object Component:</strong> Overly complex components with dozens of optional props attempting to cover all edge cases.',
    'pages.skema.komponen-blade-partial.item_12' => '<strong>Direct Database Query:</strong> Partials executing database queries directly inside Blade views.',
    'pages.skema.komponen-blade-partial.item_13' => '<strong>Markup Duplication:</strong> Copy-pasting dozens of HTML card/table lines across multiple files instead of creating a component.',
    'pages.skema.komponen-blade-partial.item_14' => '<strong>Asset Concern Mixing:</strong> Inserting page-specific JS/CSS files into global shared partials.',
    'pages.skema.komponen-blade-partial.item_2' => '<code>@@include(\'pages.sub.partials.form\')</code>: For static HTML snippets or form modal partials tightly coupled with parent context.',
    'pages.skema.komponen-blade-partial.item_3' => '<code>@@component(\'layouts.partials._toolbar\')</code>: For layout fragment UI units leveraging slot arguments.',
    'pages.skema.komponen-blade-partial.item_4' => '<code>&lt;x-ui.stat-card&gt;</code>: For cross-domain reusable anonymous/class-based components with strict <code>@@props</code> contracts.',
    'pages.skema.komponen-blade-partial.item_5' => 'Ideal for CRUD modal forms, tab partials, hint texts, or feature-specific markup not shared with other modules.',
    'pages.skema.komponen-blade-partial.item_6' => 'Strictly prohibited from placing database queries or heavy business logic inside partial files.',
    'pages.skema.komponen-blade-partial.item_7' => '<strong>Global Layout Partial Files:</strong> Prefix with an underscore (<code>_</code>) for internal layout files, e.g. <code>_toolbar.blade.php</code>.',
    'pages.skema.komponen-blade-partial.item_8' => '<strong>Feature Partial Files:</strong> Place inside feature-related <code>partials/</code> directory without underscores, e.g. <code>user-form.blade.php</code>.',
    'pages.skema.komponen-blade-partial.item_9' => '<strong>Blade Components:</strong> Place in <code>resources/views/components/&lt;category&gt;/&lt;component-name&gt;.blade.php</code>.',
    'pages.skema.komponen-blade-partial.lead' => 'Include/extend/component conventions, as well as guidance on when to use partial vs component.',
    'pages.skema.komponen-blade-partial.note_1' => 'Distinguish <code>layouts/partials</code> (global layout fragments) from <code>components</code> (API contracted reusable units/props).',
    'pages.skema.komponen-blade-partial.note_2' => 'If display requirements differ significantly, create a new component variant instead of overloading a single component with excessive props.',
    'pages.skema.komponen-blade-partial.step_1' => 'Use <strong>Blade Component (<code>&lt;x-...&gt;</code>)</strong> if you require input <code>@@props</code> validation, slot arguments, safe default values, and reuse across multiple modules.',
    'pages.skema.komponen-blade-partial.step_10' => '<strong>Zero DB Query Rule Mandatory:</strong> Partials or components must not execute database queries or heavy business logic.',
    'pages.skema.komponen-blade-partial.step_11' => '<strong>Class Component Rule:</strong> Use Class-based Components if complex data processing or formatting is required before rendering.',
    'pages.skema.komponen-blade-partial.step_12' => '<strong>Documentation Rule:</strong> Add a short docblock comment above the component to explain key props and usage examples.',
    'pages.skema.komponen-blade-partial.step_13' => 'Use <strong>Partial (<code>@@include</code>)</strong> if the UI snippet is simple, variable context is already available from the parent view, and no prop contracts are needed.',
    'pages.skema.komponen-blade-partial.step_14' => '1. Check the component repository first before creating new markup from scratch.',
    'pages.skema.komponen-blade-partial.step_15' => '<strong>Prop Contract Rule Mandatory:</strong> Reusable components must possess explicit <code>@@props</code> declarations with safe default fallbacks.',
    'pages.skema.komponen-blade-partial.step_2' => 'If a partial starts accumulating numerous optional variables and complex if-else conditions, refactor it into a Blade Component.',
    'pages.skema.komponen-blade-partial.step_3' => 'If a component is used only once without variations, consider downgrading it to a standard partial.',
    'pages.skema.komponen-blade-partial.step_4' => '2. Determine the architectural type: Partial or Blade Component based on the decision matrix.',
    'pages.skema.komponen-blade-partial.step_5' => '3. Define variable contracts (props/slots/default values) safely.',
    'pages.skema.komponen-blade-partial.step_6' => '4. Ensure mobile responsive compatibility using native Metronic utility classes.',
    'pages.skema.komponen-blade-partial.step_7' => '5. Verify bilingual translation (EN/ID) for component text labels prior to submitting PR.',
    'pages.skema.komponen-blade-partial.step_8' => '<strong>Maximum 7 Props Rule Mandatory:</strong> Limit to maximum <code>7 props</code> per component. If more, break down into sub-components or use structured data objects.',
    'pages.skema.komponen-blade-partial.step_9' => '<strong>Maximum 2 Named Slots Rule Mandatory:</strong> Limit to maximum <code>2 named slots</code> + default slot per component to maintain simplicity.',
    'pages.skema.komponen-blade-partial.warn_1' => 'If a partial is used in more than 3 locations with display variations, it is a strong signal to migrate to a Blade Component.',
    'pages.skema.layout.chip_1' => 'baseline page layout',
    'pages.skema.layout.chip_2' => 'shared layout partials',
    'pages.skema.layout.hero_title' => 'Page Layout Architecture & Blueprint (Layout Schema)',
    'pages.skema.layout.hero_lead' => 'Detailed flow of layout structure from base template, global partials, toolbar breadcrumbs, to main content slots in Metronic Laravel.',
    'pages.skema.layout.chip_1' => 'Base Layout: layouts.index',
    'pages.skema.layout.chip_2' => 'Modular Partial Components',
    'pages.skema.layout.chip_3' => '4 Essential Section Slots',
    'pages.skema.layout.chip_4' => 'Metronic Layout Engine',
    'pages.skema.layout.chip_5' => 'Responsive Fluid Container',
    'pages.skema.layout.chip_6' => 'Clean Partial Modularization',
    'pages.skema.layout.heading_1' => 'Layout Render Lifecycle (View Flow)',
    'pages.skema.layout.heading_2' => 'Key Layout Folder & File Structure',
    'pages.skema.layout.heading_3' => 'Standardized Blade Page Template Pattern',
    'pages.skema.layout.heading_4' => 'Roles & Responsibilities of 4 Core Sections',
    'pages.skema.layout.heading_5' => 'Mandatory Checklist When Creating New Pages',
    'pages.skema.layout.heading_6' => 'Layout Anti-Patterns & Common Mistakes',
    'pages.skema.layout.heading_7' => 'Team Engineering Standards & Strict Layout Rules',
    'pages.skema.layout.heading_8' => 'Layout Debugging & Troubleshooting Matrix',
    'pages.skema.layout.item_1' => '<code>@@section(\'styles\')</code>: Injects third-party CSS links or page-specific stylesheets before the <code>&lt;/head&gt;</code> tag.',
    'pages.skema.layout.item_10' => '<strong>Business Logic in View:</strong> Executing raw database queries or heavy data transformations inside Blade files.',
    'pages.skema.layout.item_11' => '<strong>Global Markup Duplication:</strong> Copy-pasting raw header/sidebar structures instead of utilizing <code>layouts.index</code>.',
    'pages.skema.layout.item_12' => '<strong>Custom Inline Style Overrides:</strong> Writing custom <code>&lt;style&gt;</code> blocks in Blade, violating UI architecture standards.',
    'pages.skema.layout.item_13' => '<strong>Global Asset Pollution:</strong> Loading heavy vendor scripts/CSS in global layout when only required on a single page.',
    'pages.skema.layout.item_2' => '<code>@@section(\'toolbar\')</code>: Supplies the page title component, navigation breadcrumbs, and action buttons via <code>layouts.partials._toolbar</code>.',
    'pages.skema.layout.item_3' => '<code>@@section(\'content\')</code>: Primary UI workspace container where cards, tables, and forms are rendered inside <code>#kt_app_content_container</code>.',
    'pages.skema.layout.item_4' => '<code>@@section(\'scripts\')</code>: Holds vendor JS scripts (DataTables, ApexCharts) and page-specific scripts at the bottom of <code>&lt;body&gt;</code>.',
    'pages.skema.layout.item_5' => 'Ensure every new page inherits the base layout via <code>@@extends(\'layouts.index\')</code>.',
    'pages.skema.layout.item_6' => 'Define the <code>toolbar</code> and <code>content</code> sections explicitly without omitting closing <code>@@endsection</code> tags.',
    'pages.skema.layout.item_7' => 'Extract CRUD modals or complex form components into <code>resources/views/pages/&lt;subfolder&gt;/partials/</code>.',
    'pages.skema.layout.item_8' => 'Load page-specific JS/CSS libraries only within the <code>styles</code> or <code>scripts</code> sections of that page.',
    'pages.skema.layout.item_9' => 'Test interface layout across desktop, tablet, and mobile breakpoints to verify container spacing and drawer toggles.',
    'pages.skema.layout.lead' => 'Flow of the layout structure from base template, partial, toolbar, to page content in Metronic Laravel.',
    'pages.skema.layout.note_1' => 'This standardization pattern ensures visual consistency, clean breadcrumb navigation, and responsive layout flexibility across all modules.',
    'pages.skema.layout.step_1' => '2. The page inherits the main base layout using <code>@@extends(\'layouts.index\')</code>.',
    'pages.skema.layout.step_2' => '3. The main layout loads global partials: Header, Sidebar, Toolbar, Footer, Drawers, and Script Bundles.',
    'pages.skema.layout.step_3' => '4. Page-specific sections (<code>styles</code>, <code>toolbar</code>, <code>content</code>, <code>scripts</code>) are injected into layout slots.',
    'pages.skema.layout.step_4' => '5. Metronic JS engine initializes UI interactivities (menu toggles, drawers, tooltips, and widgets).',
    'pages.skema.layout.step_5' => '<strong>Explicit Section Rule Mandatory:</strong> The <code>toolbar</code> and <code>content</code> sections must be explicitly defined in every page.',
    'pages.skema.layout.step_6' => '<strong>Partial Extraction Rule Mandatory:</strong> Modal forms or repeated markup blocks must be extracted into dedicated partial files.',
    'pages.skema.layout.step_7' => '<strong>Cross-Page Verification Rule Mandatory:</strong> Changes to global layout (<code>layouts/index.blade.php</code>) must be tested on at least 3 different module pages.',
    'pages.skema.layout.step_8' => '1. Controller or Route Auto-Generator invokes <code>view(\'pages.&lt;folder&gt;.&lt;name&gt;\')</code>.',
    'pages.skema.layout.step_9' => '<strong>Layout Extension Rule Mandatory:</strong> All application view pages must extend <code>layouts.index</code> unless there is a valid architectural exception.',
    'pages.skema.layout.warn_1' => 'Do not write custom <code>&lt;style&gt;</code> tags or unclosed <code>&lt;/div&gt;</code> tags that can break parent container boundaries.',
    'pages.skema.pemilihan-bahasa.chip_1' => 'default locale: en',
    'pages.skema.pemilihan-bahasa.chip_2' => 'default fallback: en',
    'pages.skema.pemilihan-bahasa.heading_1' => 'Language Flow from UI to Runtime',
    'pages.skema.pemilihan-bahasa.heading_2' => 'Implementation Point',
    'pages.skema.pemilihan-bahasa.heading_3' => 'Defaults and Fallbacks',
    'pages.skema.pemilihan-bahasa.heading_4' => 'Dynamic Menu Translation Patterns',
    'pages.skema.pemilihan-bahasa.heading_5' => 'Locale Whitelist Policy',
    'pages.skema.pemilihan-bahasa.heading_6' => 'Add New Language (example: ja)',
    'pages.skema.pemilihan-bahasa.heading_7' => 'Edge Cases and Debug Checklist',
    'pages.skema.pemilihan-bahasa.heading_8' => 'Team Standard (Strict) Locale Switch',
    'pages.skema.pemilihan-bahasa.heading_9' => 'New Locale Validation Checklist',
    'pages.skema.pemilihan-bahasa.item_1' => 'In <code>routes/web.php</code>: locale-switch endpoint <code>/lang/{locale}</code>.',
    'pages.skema.pemilihan-bahasa.item_10' => 'If the key is not available, the renderer falls back to the original title text.',
    'pages.skema.pemilihan-bahasa.item_11' => 'Create <code>lang/ja/menu.php</code>.',
    'pages.skema.pemilihan-bahasa.item_12' => 'Update locale whitelist to <code>[\'en\', \'id\', \'ja\']</code>.',
    'pages.skema.pemilihan-bahasa.item_13' => 'Add a language selector option in the user menu.',
    'pages.skema.pemilihan-bahasa.item_14' => 'Add a new language key label to the translation menu.',
    'pages.skema.pemilihan-bahasa.item_15' => 'Test language switching and check for missing keys.',
    'pages.skema.pemilihan-bahasa.item_16' => '<code>redirect()->back()</code> dependent referer; without a referrer the redirect behavior could be different.',
    'pages.skema.pemilihan-bahasa.item_17' => 'Translation files that are not in sync between locales give rise to a mixed language UI.',
    'pages.skema.pemilihan-bahasa.item_18' => 'An active cache can make language changes appear late.',
    'pages.skema.pemilihan-bahasa.item_19' => 'The main menu is fully translated with no raw keys displayed.',
    'pages.skema.pemilihan-bahasa.item_2' => '<code>app/Http/Middleware/SetLocale.php</code>: read session locale and set to runtime.',
    'pages.skema.pemilihan-bahasa.item_20' => 'The auth/error/validation page does not mix languages.',
    'pages.skema.pemilihan-bahasa.item_21' => 'Switch locale remains consistent after login/logout.',
    'pages.skema.pemilihan-bahasa.item_22' => 'There is no layout overflow on longer text.',
    'pages.skema.pemilihan-bahasa.item_3' => '<code>bootstrap/app.php</code>: middleware registration <code>SetLocale</code> in group <code>web</code>.',
    'pages.skema.pemilihan-bahasa.item_4' => '<code>resources/views/partials/menus/_user-account-menu.blade.php</code>: UI language selector.',
    'pages.skema.pemilihan-bahasa.item_5' => '<code>config/app.php</code>: default locale and fallback locale.',
    'pages.skema.pemilihan-bahasa.item_6' => 'Session is empty -> use <code>config(\'app.locale\')</code> (default <code>en</code>).',
    'pages.skema.pemilihan-bahasa.item_7' => 'Missing key -> fallback to <code>config(\'app.fallback_locale\')</code>.',
    'pages.skema.pemilihan-bahasa.item_8' => 'If it\'s still not there -> the raw key can appear in the UI.',
    'pages.skema.pemilihan-bahasa.item_9' => 'String sources: <code>lang/en/menu.php</code> and <code>lang/id/menu.php</code>.',
    'pages.skema.pemilihan-bahasa.hero_title' => 'Language Selection & Locale Architecture (Locale Architecture Blueprint)',
    'pages.skema.pemilihan-bahasa.hero_lead' => 'User locale switching flow, whitelist validation, session & SetLocale middleware management, fallback strategies, and translation key conventions.',
    'pages.skema.pemilihan-bahasa.lead' => 'The locale is selected from the user menu, stored in the session, then applied by the web middleware on each request.',
    'pages.skema.pemilihan-bahasa.note_1' => 'Quick checklist: check session locale -> check installed middleware -> check key translation -> clear cache.',
    'pages.skema.pemilihan-bahasa.step_1' => '2. Link to <code>route(\'lang.switch\', \'{locale}\')</code>.',
    'pages.skema.pemilihan-bahasa.step_10' => '1. Users click English / Indonesian in the user account menu.',
    'pages.skema.pemilihan-bahasa.step_11' => '<strong>Rule mandatory:</strong> locale switches must go through an explicit whitelist, accepting no arbitrary input.',
    'pages.skema.pemilihan-bahasa.step_2' => '3. Route <code>/lang/{locale}</code> validate whitelist locale.',
    'pages.skema.pemilihan-bahasa.step_3' => '4. Valid locales are stored with <code>session([\'locale\' => $locale])</code>.',
    'pages.skema.pemilihan-bahasa.step_4' => '5. Redirect back to the previous page.',
    'pages.skema.pemilihan-bahasa.step_5' => '6. The <code>SetLocale</code> middleware executes <code>App::setLocale()</code>.',
    'pages.skema.pemilihan-bahasa.step_6' => '7. All <code>__()</code> read language files according to the active locale.',
    'pages.skema.pemilihan-bahasa.step_7' => '<strong>Rule mandatory:</strong> when adding new locale, update route whitelist + UI selector + main domain lang file.',
    'pages.skema.pemilihan-bahasa.step_8' => '<strong>Rule required:</strong> fallback locale must remain defined to prevent empty UI.',
    'pages.skema.pemilihan-bahasa.step_9' => '<strong>Rule mandatory:</strong> locale changes must be tested across pages and across user roles.',
    'pages.skema.pemilihan-bahasa.warn_1' => 'When adding a new language, the whitelist must be updated. Otherwise, the new locale will not be saved.',
    'pages.skema.route.hero_title' => 'Page Routing Architecture & Blueprint (Route Schema)',
    'pages.skema.route.hero_lead' => 'Detailed lifecycle of browser URL requests to Blade views, automatic route generator mechanisms (routes/menu-temp.php & routes/menu.php), and strict application route registration standards.',
    'pages.skema.route.chip_1' => 'Source of Truth: View Folder Structure',
    'pages.skema.route.chip_2' => 'Auto Route & URL Naming',
    'pages.skema.route.chip_3' => 'php artisan route:list --name=help.programming',
    'pages.skema.route.heading_1' => 'Request Lifecycle Flow (URL to View)',
    'pages.skema.route.heading_2' => 'Blade File to Route Conversion Mechanics',
    'pages.skema.route.heading_3' => 'Route File Architectural Responsibilities',
    'pages.skema.route.heading_4' => 'Quick Guide: Adding a New View Page',
    'pages.skema.route.heading_5' => 'Live Route Mapping & Inspection Commands',
    'pages.skema.route.heading_6' => 'Route Evaluation Priority & Order',
    'pages.skema.route.heading_7' => 'Team Engineering Standards & Strict Rules',
    'pages.skema.route.heading_8' => 'Route Debugging & Troubleshooting Matrix',
    'pages.skema.route.item_1' => '<code>routes/web.php</code>: Main entry point handling custom explicit routes, Resource Controllers, Auth, Profile, language switcher (<code>/lang/{locale}</code>), and importing generator routes.',
    'pages.skema.route.item_2' => '<code>routes/menu-temp.php</code>: Automatic route generator mapping static Blade views in the <code>resources/views/pages</code> directory.',
    'pages.skema.route.item_3' => '<code>routes/menu.php</code>: Database-driven dynamic menu route generator configured via <code>config/menu_seeder.php</code>.',
    'pages.skema.route.item_10' => '<code>routes/auth.php</code>: Default authentication endpoints (Login, Register, Logout, Password Reset).',
    'pages.skema.route.item_11' => '<strong>Route Not Found (404):</strong> Check the Blade file name and ensure it is placed inside <code>resources/views/pages</code> without a leading <code>_</code> or inside a <code>partials/</code> subfolder.',
    'pages.skema.route.item_12' => '<strong>Redirect to Login / 403 Forbidden:</strong> Ensure the user is authenticated as all auto-generated view routes are protected by <code>auth</code> middleware.',
    'pages.skema.route.item_13' => '<strong>Unreflected Route Changes:</strong> Run <code>php artisan route:clear</code> and <code>php artisan view:clear</code> commands in development/staging environments.',
    'pages.skema.route.item_14' => '<strong>Route Name Collision:</strong> Inspect <code>php artisan route:list</code> results to detect duplications between explicit <code>web.php</code> routes and auto generators.',
    'pages.skema.route.item_4' => 'Create a new Blade file in <code>resources/views/pages/&lt;subfolder&gt;/&lt;page-name&gt;.blade.php</code>.',
    'pages.skema.route.item_5' => 'The Route Name and URL are generated automatically without modifying <code>routes/web.php</code>.',
    'pages.skema.route.item_6' => 'Add menu configuration in <code>config/sidebar/_sidebar_*.php</code> if you want the page to appear in top/side navigation.',
    'pages.skema.route.item_7' => 'Explicit routes defined early in <code>routes/web.php</code> take priority over auto-generator matching.',
    'pages.skema.route.item_8' => 'Resource Controllers and explicit endpoints hold higher priority than static auto view routes.',
    'pages.skema.route.item_9' => '<code>Route::fallback()</code> is always placed at the very end to catch invalid URLs and render the 404 error page.',
    'pages.skema.route.lead' => 'Request path from URL to Blade in this project: manual route + auto route generator.',
    'pages.skema.route.note_1' => 'All automatic route generators are wrapped within the <code>auth</code> middleware, while <code>Route::fallback()</code> remains outside to handle 404s globally.',
    'pages.skema.route.step_1' => 'User sends an HTTP URL request via browser (e.g., <code>/help/pemrograman/skema/route</code>).',
    'pages.skema.route.step_2' => 'Laravel processes <code>routes/web.php</code> and checks for explicit routes or registered controllers.',
    'pages.skema.route.step_3' => '<code>routes/web.php</code> executes <code>require routes/menu-temp.php</code> for static view route mapping.',
    'pages.skema.route.step_4' => '<code>routes/menu-temp.php</code> loops through all <code>resources/views/pages/*.blade.php</code> files (skipping partials & files starting with <code>_</code>).',
    'pages.skema.route.step_5' => 'Each Blade file becomes an automatic GET route protected by <code>auth</code> middleware.',
    'pages.skema.route.step_6' => 'If the URL does not match any manual route or auto generator, Laravel redirects to <code>Route::fallback()</code> (404 Page).',
    'pages.skema.route.step_7' => '<strong>Auth Rule Mandatory:</strong> All internal application view routes must be protected by <code>auth</code> middleware.',
    'pages.skema.route.step_8' => '<strong>Cache Compatibility Rule Mandatory:</strong> Avoid using Route Closures in production <code>routes/web.php</code> so that <code>php artisan route:cache</code> runs without error.',
    'pages.skema.route.step_9' => '<strong>Kebab-Case Naming Rule Mandatory:</strong> All Blade file names and subfolders must use lowercase <code>kebab-case</code> format.',
    'pages.skema.route.step_10' => '<strong>Route List Audit Rule Mandatory:</strong> Every new route or page must appear and be verified in <code>php artisan route:list</code> before approving pull requests.',
    'pages.skema.route.warn_1' => 'Avoid duplicate file names across subfolders and use <code>kebab-case</code> format for clean and predictable URLs.',
    'pages.skema.sidebar-menu.hero_title' => 'Sidebar Menu Architecture & Recursive Renderer (Sidebar Blueprint)',
    'pages.skema.sidebar-menu.hero_lead' => 'Declarative sidebar menu data structures, _menu-item.blade.php recursive rendering flow, Dashboard Show More/Less mechanism, accordion vs dropdown modes, and active state rules.',
    'pages.skema.sidebar-menu.chip_1' => 'children = parent node',
    'pages.skema.sidebar-menu.chip_2' => 'without children = leaf link',
    'pages.skema.sidebar-menu.chip_3' => 'Show More / Less toggle',
    'pages.skema.sidebar-menu.chip_4' => 'auto open on active route',
    'pages.skema.sidebar-menu.chip_5' => 'desktop + mobile compatible',
    'pages.skema.sidebar-menu.heading_1' => 'Core Primary Source File Map (Lifecycle)',
    'pages.skema.sidebar-menu.heading_2' => 'Basic Sidebar Menu Data Structure',
    'pages.skema.sidebar-menu.heading_3' => 'Menu Render Modes (Accordion vs Flyout Dropdown)',
    'pages.skema.sidebar-menu.heading_4' => 'Badge & Navigation Target Configuration',
    'pages.skema.sidebar-menu.heading_5' => 'Unique Dashboard Features: Show More / Show Less',
    'pages.skema.sidebar-menu.heading_6' => 'Recursive Active State Evaluation Logic',
    'pages.skema.sidebar-menu.heading_7' => 'Team Engineering Standards & Strict Sidebar Rules',
    'pages.skema.sidebar-menu.heading_8' => 'Sidebar Debugging & Troubleshooting Matrix',
    'pages.skema.sidebar-menu.item_1' => '<code>config/sidebar/_sidebar_dashboard.php</code> (primary dashboard menu + collapsed show more config).',
    'pages.skema.sidebar-menu.item_10' => 'Before publishing: validate route validity, badges, target links, dropdown behavior, and mobile viewport compatibility.',
    'pages.skema.sidebar-menu.item_11' => '<strong>Menu Item Missing in Sidebar:</strong> Verify correct config file inclusion in <code>_menu.blade.php</code> and validate array syntax.',
    'pages.skema.sidebar-menu.item_12' => '<strong>Untranslated Title:</strong> Check normalized <code>menu.*</code> key and ensure key is registered in lang files.',
    'pages.skema.sidebar-menu.item_2' => '<code>config/sidebar/_sidebar_apps.php</code> (nested menus, status badges, and flyout dropdown mode).',
    'pages.skema.sidebar-menu.item_3' => '<code>config/sidebar/_sidebar_helps.php</code> (internal application documentation menu).',
    'pages.skema.sidebar-menu.item_4' => '<strong>Parent Accordion Not Auto-Opening:</strong> Check wildcard <code>routeIs</code> pattern on currently active child route.',
    'pages.skema.sidebar-menu.item_5' => '<strong>Empty / Broken Icon:</strong> Verify valid Keenicons class and ensure <code>paths</code> count matches duotone spans.',
    'pages.skema.sidebar-menu.item_6' => '<code>resources/views/layouts/partials/sidebar/_menu.blade.php</code> (sidebar main navigation wrapper).',
    'pages.skema.sidebar-menu.item_7' => '<code>resources/views/layouts/partials/sidebar/_menu-item.blade.php</code> (recursive Blade partial rendering parent & leaf items).',
    'pages.skema.sidebar-menu.item_8' => 'Parent active state is calculated recursively; leaf items use <code>request()->routeIs($route . \'*\')</code>.',
    'pages.skema.sidebar-menu.item_9' => 'Title string is automatically transformed into <code>menu.*</code> key; falls back to original text if missing.',
    'pages.skema.sidebar-menu.lead' => 'Declarative sidebar menu data structures, _menu-item.blade.php recursive rendering flow, Dashboard Show More/Less mechanism, accordion vs dropdown modes, and active state rules.',
    'pages.skema.sidebar-menu.note_1' => 'Dropdown Mode Note: In <code>dropdown => true</code> mode, parent <code>target</code> attribute is automatically applied to child items inside the dropdown.',
    'pages.skema.sidebar-menu.step_1' => '<code>children</code> + <code>\'dropdown\' => true</code> renders as a floating popup dropdown item (flyout).',
    'pages.skema.sidebar-menu.step_2' => '<code>menus_dashboard_collapsed</code> stores additional items hidden by default in collapsed mode.',
    'pages.skema.sidebar-menu.step_3' => 'The "Show X More" / "Show Less" toggle button is calculated dynamically based on collapsed item count.',
    'pages.skema.sidebar-menu.step_4' => 'If active route resides inside collapsed items, the collapsed panel expands automatically.',
    'pages.skema.sidebar-menu.step_5' => '<strong>Icon Validation Rule Mandatory:</strong> Level-1 icons must use valid Keenicons class + matching <code>paths</code> count for duotone spans.',
    'pages.skema.sidebar-menu.step_6' => '<strong>Menu Translation Rule Mandatory:</strong> Translation key <code>menu.*</code> must exist in both <code>lang/en/menu.php</code> and <code>lang/id/menu.php</code> for all primary items.',
    'pages.skema.sidebar-menu.step_7' => '<strong>Active State Testing Rule Mandatory:</strong> Nested menu changes must be tested down to the deepest child route to ensure parent auto-opens.',
    'pages.skema.sidebar-menu.step_8' => '<code>menus_dashboard</code> = primary core menu items always visible at top of sidebar.',
    'pages.skema.sidebar-menu.step_9' => '<code>children</code> + without <code>dropdown</code> -> rendered as nested accordion menu.',
    'pages.skema.sidebar-menu.warn_1' => 'Changes to nested menu structures must be tested on the deepest active child route to ensure automatic parent opening (active/here/show) functions as expected.',
    'pages.skema.struktur-config-menu.hero_title' => 'Menu Configuration Architecture (Menu Config Blueprint)',
    'pages.skema.struktur-config-menu.hero_lead' => 'Declarative menu data structures in config/sidebar/* and config/header/*, dynamic menu.* translation engine, recursive Blade renderer, and active state logic.',
    'pages.skema.struktur-config-menu.chip_1' => 'config/sidebar/*',
    'pages.skema.struktur-config-menu.chip_2' => 'config/header/*',
    'pages.skema.struktur-config-menu.chip_3' => 'lang/*/menu.php',
    'pages.skema.struktur-config-menu.chip_4' => '_menu-item.blade.php',
    'pages.skema.struktur-config-menu.chip_5' => 'Recursive Active State',
    'pages.skema.struktur-config-menu.heading_1' => 'Menu Data Orchestration Flow (Lifecycle)',
    'pages.skema.struktur-config-menu.heading_2' => 'Core Menu Configuration File Map',
    'pages.skema.struktur-config-menu.heading_3' => 'PHP Menu Data Structure Contract',
    'pages.skema.struktur-config-menu.heading_4' => 'Recursive Blade Renderer Flow',
    'pages.skema.struktur-config-menu.heading_5' => 'Menu Title Translation Key Normalization Engine',
    'pages.skema.struktur-config-menu.heading_6' => 'Active State Rules & Recursive Evaluation Logic',
    'pages.skema.struktur-config-menu.heading_7' => 'Checklist & Steps to Add New Menu Items',
    'pages.skema.struktur-config-menu.heading_8' => 'Menu Configuration Debugging & Troubleshooting Matrix',
    'pages.skema.struktur-config-menu.heading_9' => 'Real Implementation Example Before/After (_sidebar_helps.php)',
    'pages.skema.struktur-config-menu.item_1' => '<code>config/sidebar/_sidebar_*.php</code> for sidebar menu config files per domain (dashboard, pages, apps, layouts, helps).',
    'pages.skema.struktur-config-menu.item_10' => 'Leaf menu is active if <code>request()->routeIs($route . \'*\')</code> evaluates to true.',
    'pages.skema.struktur-config-menu.item_11' => 'Parent menu automatically receives <code>active</code>, <code>here</code>, and <code>show</code> states if at least one child is active (recursive).',
    'pages.skema.struktur-config-menu.item_12' => 'Dropdown mode also utilizes child route evaluation to apply active styling classes.',
    'pages.skema.struktur-config-menu.item_13' => 'Dashboard features special show more/show less behavior controlled by the <code>menus_dashboard_collapsed</code> array.',
    'pages.skema.struktur-config-menu.item_14' => '<strong>Title Not Translated:</strong> Check normalized <code>menu.*</code> key name and ensure key exists in both <code>lang/en/menu.php</code> and <code>lang/id/menu.php</code>.',
    'pages.skema.struktur-config-menu.item_15' => '<strong>Parent Menu Not Auto-Opening:</strong> Verify child route name match and ensure wildcard <code>routeIs</code> covers all sub-routes.',
    'pages.skema.struktur-config-menu.item_16' => '<strong>Empty / Broken Icon:</strong> Ensure valid icon class (e.g. <code>ki-duotone ki-element-11</code>) and correct <code>paths</code> count matching duotone spans.',
    'pages.skema.struktur-config-menu.item_17' => '<strong>Config Changes Unreflected:</strong> Execute <code>php artisan config:clear</code> and <code>php artisan view:clear</code> if environment caching is enabled.',
    'pages.skema.struktur-config-menu.item_2' => '<code>config/header/_header_*.php</code> for mega menu header configuration files.',
    'pages.skema.struktur-config-menu.item_3' => '<code>resources/views/layouts/partials/sidebar/_menu.blade.php</code> as the sidebar renderer entry point.',
    'pages.skema.struktur-config-menu.item_4' => '<code>resources/views/layouts/partials/sidebar/_menu-item.blade.php</code> for recursive rendering of parent/child menus.',
    'pages.skema.struktur-config-menu.item_5' => '<code>lang/en/menu.php</code> and <code>lang/id/menu.php</code> as menu label translation dictionaries.',
    'pages.skema.struktur-config-menu.item_6' => '<code>app/Helpers/GetPageTitle.php</code> for mapping toolbar page titles based on the currently active route.',
    'pages.skema.struktur-config-menu.item_7' => 'Example: <code>Cache &amp; Deployment Scheme</code> &rarr; <code>menu.cache_and_deployment_scheme</code>.',
    'pages.skema.struktur-config-menu.item_8' => 'Ensure exact matching keys are available in both <code>lang/en/menu.php</code> and <code>lang/id/menu.php</code>.',
    'pages.skema.struktur-config-menu.item_9' => 'If title changes in config, the translation key automatically adjusts since it is derived from title text.',
    'pages.skema.struktur-config-menu.lead' => 'Declarative menu data structures in config/sidebar/* and config/header/*, dynamic menu.* translation engine, recursive Blade renderer, and active state logic.',
    'pages.skema.struktur-config-menu.note_1' => 'Minimum leaf item attributes: <code>title + route</code> or <code>title + href</code>. Parent nodes generally include a <code>children</code> array.',
    'pages.skema.struktur-config-menu.step_1' => 'The view renderer parses configuration files to construct UI menu components in sidebar and header.',
    'pages.skema.struktur-config-menu.step_10' => '5. Verify icon class and <code>paths</code> count to ensure duotone icons render perfectly.',
    'pages.skema.struktur-config-menu.step_11' => 'Ensure target route is registered (in this project, help routes are auto-generated from Blade files under <code>resources/views/pages</code>).',
    'pages.skema.struktur-config-menu.step_12' => 'Add title translation key to <code>lang/en/menu.php</code> and <code>lang/id/menu.php</code> to support multi-language labels.',
    'pages.skema.struktur-config-menu.step_13' => 'Files <code>config/sidebar/*</code> and <code>config/header/*</code> store declarative menu tree structures.',
    'pages.skema.struktur-config-menu.step_14' => '<code>_menu.blade.php</code> invokes each config group (dashboard, pages, apps, layouts, help).',
    'pages.skema.struktur-config-menu.step_15' => '1. Add new items in sidebar/header configs following consistent array structure.',
    'pages.skema.struktur-config-menu.step_16' => 'Add new child element into <code>children[]</code> array with paired <code>title</code> and <code>route</code>.',
    'pages.skema.struktur-config-menu.step_2' => 'Menu title is normalized into key <code>menu.*</code>; if key is missing, system falls back to original title text.',
    'pages.skema.struktur-config-menu.step_3' => 'Active route is recursively evaluated to apply <code>active/here/show</code> classes on parent-child elements.',
    'pages.skema.struktur-config-menu.step_4' => 'Each element is passed to recursive partial <code>_menu-item.blade.php</code>.',
    'pages.skema.struktur-config-menu.step_5' => 'If <code>children</code> exist: rendered recursively; parent automatically opens when child below is active.',
    'pages.skema.struktur-config-menu.step_6' => 'If leaf item: renders link + badge + active indicator based on <code>request()->routeIs(...)</code>.',
    'pages.skema.struktur-config-menu.step_7' => '2. Ensure route name is valid via <code>php artisan route:list</code>.',
    'pages.skema.struktur-config-menu.step_8' => '3. Add EN and ID translation keys matching normalized title string.',
    'pages.skema.struktur-config-menu.step_9' => '4. Test parent-child active states on desktop and mobile viewports.',
    'pages.skema.theme-assets.hero_title' => 'Theme Assets Architecture & Load Sequence (Blueprint)',
    'pages.skema.theme-assets.hero_lead' => 'Detailed load sequence of global and page-specific assets to ensure Metronic UI stability, performance, dependency safety, and maintainability.',
    'pages.skema.theme-assets.chip_1' => 'Global Assets First',
    'pages.skema.theme-assets.chip_2' => 'Page Assets Last',
    'pages.skema.theme-assets.chip_3' => 'Dependency Load Order',
    'pages.skema.theme-assets.chip_4' => 'ThemeAsset Resolver',
    'pages.skema.theme-assets.chip_5' => 'FOUC Prevention',
    'pages.skema.theme-assets.heading_1' => 'Base Layout Load Sequence (Lifecycle)',
    'pages.skema.theme-assets.heading_2' => 'Real Implementation in layouts/index.blade.php',
    'pages.skema.theme-assets.heading_3' => 'Blade Asset Resolver Standards (ThemeAsset::url)',
    'pages.skema.theme-assets.heading_4' => 'Page-Specific Asset Loading Pattern',
    'pages.skema.theme-assets.heading_5' => 'Theme Modes & Body Data Attributes',
    'pages.skema.theme-assets.heading_6' => 'Checklist When Adding New Assets',
    'pages.skema.theme-assets.heading_7' => 'Team Engineering Standards & Strict Rules',
    'pages.skema.theme-assets.heading_8' => 'Asset Debugging & Troubleshooting Matrix',
    'pages.skema.theme-assets.item_1' => '<code>ThemeAsset::url()</code> or <code>asset()</code> for theme asset files (CSS, JS, SVG icons, images).',
    'pages.skema.theme-assets.item_10' => 'Attributes <code>data-kt-app-layout</code> and sub-configs on the <code>&lt;body&gt;</code> tag control visual behavior and Metronic JS components.',
    'pages.skema.theme-assets.item_11' => 'Determine asset classification: whether required globally across all pages or page-specifically.',
    'pages.skema.theme-assets.item_12' => 'Ensure correct dependency order: vendor plugins must load before caller scripts.',
    'pages.skema.theme-assets.item_13' => 'Avoid re-importing JS/CSS libraries already included in <code>plugins.bundle.js</code> (e.g., SweetAlert2, Flatpickr).',
    'pages.skema.theme-assets.item_14' => 'Test initial page render performance and FOUC behavior after adding new assets.',
    'pages.skema.theme-assets.item_15' => 'If using build tools or caches, execute required view and browser cache clearing commands.',
    'pages.skema.theme-assets.item_16' => '<strong>UI Layout Unformatted:</strong> Check CSS load order; ensure <code>plugins.bundle.css</code> and <code>style.bundle.css</code> load properly.',
    'pages.skema.theme-assets.item_17' => '<strong>Dead JS Interactivity / Uncaught ReferenceError:</strong> Verify load sequence: <code>plugins.bundle.js</code> &rarr; <code>scripts.bundle.js</code> &rarr; <code>@@yield(\'scripts\')</code>.',
    'pages.skema.theme-assets.item_18' => '<strong>Style Changes Unreflected:</strong> Perform browser hard refresh (Ctrl+F5) and clear view cache via <code>php artisan view:clear</code>.',
    'pages.skema.theme-assets.item_19' => '<strong>Undefined Plugin Error (e.g. DataTable is not a function):</strong> Ensure vendor bundles (e.g. <code>datatables.bundle.js</code>) are placed inside <code>scripts</code> after main bundles.',
    'pages.skema.theme-assets.item_2' => '<code>route()</code> or <code>url()</code> specifically for application page navigation URLs.',
    'pages.skema.theme-assets.item_3' => 'Strictly forbidden to hardcode raw version folders like <code>/assets-v2</code> or <code>/assets-v3</code> in Blade.',
    'pages.skema.theme-assets.item_4' => 'Pages can inject custom stylesheets via <code>@@section(\'styles\')</code> before main theme bundles.',
    'pages.skema.theme-assets.item_5' => 'Pages can inject custom JS scripts via <code>@@section(\'scripts\')</code> at the bottom before closing <code>&lt;/body&gt;</code>.',
    'pages.skema.theme-assets.item_6' => 'Feature modules load additional plugins: <code>fullcalendar.bundle.js</code>, <code>datatables.bundle.js</code>.',
    'pages.skema.theme-assets.item_7' => 'Heavy custom libraries must not be placed in global layout if used on only one or two pages.',
    'pages.skema.theme-assets.item_8' => 'Partial <code>partials.theme-mode._init</code> executes inline script in <code>&lt;head&gt;</code> reading theme mode (dark/light) from localStorage to prevent FOUC.',
    'pages.skema.theme-assets.item_9' => 'Body data attributes control layout mode (dark-sidebar, light-header, fixed-sidebar).',
    'pages.skema.theme-assets.lead' => 'Detailed load sequence of global and page-specific assets to ensure Metronic UI stability, performance, dependency safety, and maintainability.',
    'pages.skema.theme-assets.note_1' => 'For dynamic Metronic version switching architecture, see: <code>help/programming/operational/metronic-version-switching-guide</code>.',
    'pages.skema.theme-assets.note_2' => 'Core Principle: Global assets form the UI foundation, while page-specific assets serve specific feature requirements.',
    'pages.skema.theme-assets.step_1' => '2. Mandatory Global CSS: <code>assets/plugins/global/plugins.bundle.css</code>.',
    'pages.skema.theme-assets.step_2' => '3. Mandatory Theme CSS: <code>assets/css/style.bundle.css</code>.',
    'pages.skema.theme-assets.step_3' => '4. In Footer: Mandatory Global JS <code>plugins.bundle.js</code> followed by <code>scripts.bundle.js</code>.',
    'pages.skema.theme-assets.step_4' => '5. Finally <code>@@yield(\'scripts\')</code> for page-specific JS scripts.',
    'pages.skema.theme-assets.step_5' => '<strong>Asset Scope Rule Mandatory:</strong> Page-specific assets must not be included globally without clear performance justification.',
    'pages.skema.theme-assets.step_6' => '<strong>Zero Duplication Rule Mandatory:</strong> Duplicate cross-section asset file imports must be eliminated before merging.',
    'pages.skema.theme-assets.step_7' => '<strong>Multi-Device Testing Rule Mandatory:</strong> Every asset configuration change must be tested on desktop and mobile viewports.',
    'pages.skema.theme-assets.step_8' => '1. <code>@@yield(\'styles\')</code> for page-specific vendor stylesheets.',
    'pages.skema.theme-assets.step_9' => '<strong>Dependency Order Rule Mandatory:</strong> New plugins must document their dependency chain (CSS/JS load order).',
    'pages.skema.theme-assets.warn_1' => 'Modifying layout attributes on <code>&lt;body&gt;</code> without asset/script synchronization can cause visual anomalies on Metronic components.',
