    'pages.skema.manajemen-pengguna.hero_lead' => 'Explanation of data architecture, controller flow, and programming blueprint for all User Management sub-modules: User, Role, Permission, Role Access, User Access, and Password Reset.',
    'pages.operasional.manajemen-pengguna.hero_title' => 'User Management Operational Guide & Workflow',
    'pages.operasional.manajemen-pengguna.hero_lead' => 'Operational guide and workflow for user management, role & permission access control, password reset, registration approval, avatars, and reward points.',

    // Pages - Skema & Operasional App Support
    'pages.skema.app-support.hero_title' => 'App Support Module Schema & Architecture',
    'pages.skema.app-support.hero_lead' => 'Explanation of data architecture, controller flow, and programming blueprint for all App Support sub-modules: Dynamic Menu, App Profile, Feature Flags, Database Backup, and Login Data.',
    'pages.operasional.app-support.hero_title' => 'App Support Operational Guide & Workflow',
    'pages.operasional.app-support.hero_lead' => 'Operational guide and workflow for app menu management, app profile identity, feature flags, DB backup export/restore, and login data audit trails.',

    // Pages - Skema SweetAlert2
    'pages.skema.sweetalert2.hero_title' => 'JavaScript SwalHelper (SweetAlert2) Scheme & Standardization',
    'pages.skema.sweetalert2.hero_lead' => 'Comprehensive guide to using the global JavaScript helper SwalHelper for CRUD notifications, delete confirmations, and AJAX 422 XHR validation error handling.',
    'sweetalert2_skema_desc' => 'Global standardization of JavaScript helper <code>SwalHelper</code> for CRUD notifications, delete confirmation, and 422 XHR validation.',

    // Pages - Operasional Panduan Tambah Halaman
    'pages.operasional.panduan-tambah-halaman.hero_title' => 'Operational Guide: How to Add a New Page',
    'pages.operasional.panduan-tambah-halaman.hero_lead' => 'Step-by-step practical guide for developers to add new pages, create controllers & form partials, configure navigation, and apply CRUD standards.',
    'pages.operasional.panduan-tambah-halaman.lead' => 'Developer workflow guide for adding new pages, automatic route registration, core layout preservation, and CRUD standardization.',
    'pages.operasional.panduan-tambah-halaman.chip_1' => 'Zero Route Config',
    'pages.operasional.panduan-tambah-halaman.chip_2' => 'Multi-Tab Single Route',
    'pages.operasional.panduan-tambah-halaman.chip_3' => 'Responsive Table Native',
    'pages.operasional.panduan-tambah-halaman.chip_4' => 'SwalHelper Global',
    'pages.operasional.panduan-tambah-halaman.heading_1' => 'Daily Developer Workflow (Adding New Page)',
    'pages.operasional.panduan-tambah-halaman.heading_2' => 'Automatic Naming & Routing Example',
    'pages.operasional.panduan-tambah-halaman.heading_3' => 'Multi-Tab Layout & Core Layout Rules',
    'pages.operasional.panduan-tambah-halaman.heading_4' => 'Responsive Table Creation Rules',
    'pages.operasional.panduan-tambah-halaman.heading_5' => 'Controller, Model & Form Partial Structure',
    'pages.operasional.panduan-tambah-halaman.heading_6' => 'CRUD Notification JS Helper (SwalHelper)',
    'pages.operasional.panduan-tambah-halaman.heading_7' => 'Top Tooltips & Modal Trigger Wrapper',
    'pages.operasional.panduan-tambah-halaman.heading_8' => 'Inspection Command & Release Verification',
    'pages.operasional.panduan-tambah-halaman.heading_9' => 'Team Standard & Strict Rules (Page Onboarding)',
    'pages.operasional.panduan-tambah-halaman.step_5' => '1. Create a new Blade file at <code>resources/views/pages/&lt;folder&gt;/&lt;page&gt;.blade.php</code>.',
    'pages.operasional.panduan-tambah-halaman.step_1' => '2. GET route &amp; URL are automatically registered via <code>routes/menu-temp.php</code>.',
    'pages.operasional.panduan-tambah-halaman.step_2' => '3. Create Controller &amp; Model mirrored at <code>App\\Http\\Controllers\\&lt;Folder&gt;\\&lt;Page&gt;Controller</code>.',
    'pages.operasional.panduan-tambah-halaman.step_3' => '4. Extract CRUD Form partial to <code>resources/views/pages/&lt;folder&gt;/partials/&lt;feature&gt;-form.blade.php</code>.',
    'pages.operasional.panduan-tambah-halaman.step_4' => '5. Register menu navigation in <code>config/sidebar/_sidebar_*.php</code> and <code>lang/*/menu.php</code>.',
    'pages.operasional.panduan-tambah-halaman.step_6' => '<strong>Zero Layout Mutation Rule Mandatory:</strong> Core layout &amp; menu seeders must never be modified just to add sub-tabs.',
    'pages.operasional.panduan-tambah-halaman.step_7' => '<strong>Mirror Folder Structure Rule Mandatory:</strong> Controller, Model, &amp; Form Request locations must precisely mirror the Blade view location.',
    'pages.operasional.panduan-tambah-halaman.step_8' => '<strong>SwalHelper Only Rule Mandatory:</strong> All SweetAlert notifications must be centralized using the global <code>SwalHelper</code>.',
    'pages.operasional.panduan-tambah-halaman.step_9' => '<strong>Top Tooltips Rule Mandatory:</strong> Every icon-only button (btn-icon) must use Bootstrap 5 top tooltips &amp; modal trigger wrappers.',
    'pages.operasional.panduan-tambah-halaman.item_1' => '<strong>Do Not Modify Core Layout:</strong> Never modify <code>_menu-item.blade.php</code>, <code>navs.blade.php</code>, or menu seeders for sub-tabs.',
    'pages.operasional.panduan-tambah-halaman.item_2' => '<strong>Multi-Tab Single-Route Architecture:</strong> Use a single route (e.g. <code>/user-profile?tab=...</code>) and <code>@@include</code> tab partials.',
    'pages.operasional.panduan-tambah-halaman.item_3' => '<strong>Blade Partial Cleanliness:</strong> Tab partial files must NOT contain <code>@@endsection</code>, <code>@@extends</code>, or main <code>&lt;/div&gt;</code> closing tags.',
    'pages.operasional.panduan-tambah-halaman.item_4' => '<strong>Script Bundles:</strong> <code>@@section(\'scripts\')</code> must load supporting JS bundles (<code>widgets.bundle.js</code>, <code>datatables.bundle.js</code>).',
    'pages.operasional.panduan-tambah-halaman.item_5' => '<strong>No Custom CSS:</strong> Do not write custom <code>&lt;style&gt;</code> blocks. Rely strictly on native Metronic &amp; Bootstrap 5 classes.',
    'pages.operasional.panduan-tambah-halaman.item_6' => '<strong>Native Responsive Wrapper:</strong> Always wrap data tables with <code>&lt;div class="table-responsive"&gt;</code>.',
    'pages.operasional.panduan-tambah-halaman.item_7' => '<strong>Column Width Preservation:</strong> Use Metronic\'s native minimum width classes (<code>min-w-200px</code>, <code>min-w-150px</code>, <code>min-w-125px</code>) on <code>&lt;th&gt;</code>.',
    'pages.operasional.panduan-tambah-halaman.item_8' => '<strong>Mirror Folder Structure:</strong> Controllers &amp; Models must be placed in subfolders mirroring the Blade view structure.',
    'pages.operasional.panduan-tambah-halaman.item_9' => '<strong>Form Partial Extraction:</strong> CRUD modal forms must be extracted to <code>resources/views/pages/&lt;folder&gt;/partials/&lt;feature&gt;-form.blade.php</code>.',
    'pages.operasional.panduan-tambah-halaman.item_10' => '<strong>Form Request Validation Mirroring:</strong> Validation rules must be extracted to <code>App\\Http\\Requests\\&lt;SubFolder&gt;\\&lt;FeatureRequest&gt;.php</code>.',
    'pages.operasional.panduan-tambah-halaman.item_11' => '<strong>Global SwalHelper:</strong> CRUD notifications must use <code>SwalHelper.success()</code>, <code>SwalHelper.error()</code>, <code>SwalHelper.validationError(xhr)</code>, &amp; <code>SwalHelper.confirmDelete()</code>.',
    'pages.operasional.panduan-tambah-halaman.item_12' => '<strong>Mandatory Top Tooltips:</strong> Every <code>btn-icon</code> must use <code>data-bs-toggle="tooltip" data-bs-placement="top" title="..."</code>.',
    'pages.operasional.panduan-tambah-halaman.item_13' => '<strong>Modal Trigger Tooltip Wrapper:</strong> Wrap modal trigger buttons inside <code>&lt;span data-bs-toggle="tooltip" data-bs-placement="top" title="..."&gt;</code> to prevent attribute collision.',
    'pages.operasional.panduan-tambah-halaman.note_1' => 'Blade files prefixed with an underscore (_) or located inside partials/ subfolders are automatically ignored by the auto route generator.',
    'pages.operasional.panduan-tambah-halaman.warn_1' => 'Always run php artisan view:clear and route:clear if new routes or views do not immediately reflect in the browser.',

    // Pages - Operasional Panduan Tambah Menu
    'pages.operasional.panduan-tambah-menu.hero_title' => 'Operational Guide: How to Add Navigation Menus',
    'pages.operasional.panduan-tambah-menu.hero_lead' => 'Step-by-step practical guide to configuring sidebar & header menus, category-based seeder modularization, route vs href strategy, optional attributes (badge, target, icon), and active state verification.',
    'pages.operasional.panduan-tambah-menu.lead' => 'Developer workflow guide for adding new navigation menu items to sidebar and header navigation.',
    'pages.operasional.panduan-tambah-menu.chip_1' => 'Declarative Array Config',
    'pages.operasional.panduan-tambah-menu.chip_2' => 'Modular Seeder per Category',
    'pages.operasional.panduan-tambah-menu.chip_3' => 'Route vs Href Strategy',
    'pages.operasional.panduan-tambah-menu.chip_4' => 'Optional Features (Badge, Target)',
    'pages.operasional.panduan-tambah-menu.heading_1' => '3 Core Steps to Add a New Menu Item',
    'pages.operasional.panduan-tambah-menu.heading_2' => 'Config Modularization & Menu Seeders by Category',
    'pages.operasional.panduan-tambah-menu.heading_3' => 'Decision Guide: When to Use route vs href',
    'pages.operasional.panduan-tambah-menu.heading_4' => 'Menu Configuration Optional Attributes & Features',
    'pages.operasional.panduan-tambah-menu.heading_5' => 'PHP Menu Array Data Structure Contract',
    'pages.operasional.panduan-tambah-menu.heading_6' => 'Title Translation Key Normalization Engine',
    'pages.operasional.panduan-tambah-menu.heading_7' => 'Active State Rules & Evaluation',
    'pages.operasional.panduan-tambah-menu.heading_8' => 'Menu Debug & Troubleshooting Guide',
    'pages.operasional.panduan-tambah-menu.heading_9' => 'Team Standard & Strict Rules (Menu Operations)',
    'pages.operasional.panduan-tambah-menu.step_3' => '1. Config title string is converted automatically to snake_case <code>menu.*</code> format.',
    'pages.operasional.panduan-tambah-menu.step_1' => '2. Blade renderer looks up the key in <code>lang/&lt;locale&gt;/menu.php</code>.',
    'pages.operasional.panduan-tambah-menu.step_2' => '3. If the key is missing, system falls back to rendering the raw title text without error.',
    'pages.operasional.panduan-tambah-menu.item_1' => 'Edit the appropriate domain config file in <code>config/sidebar/_sidebar_*.php</code> or <code>config/header/_header_*.php</code>.',
    'pages.operasional.panduan-tambah-menu.item_2' => 'Add the title translation key in <code>lang/en/menu.php</code> and <code>lang/id/menu.php</code> according to <code>menu.*</code> rules.',
    'pages.operasional.panduan-tambah-menu.item_3' => 'Verify route availability (<code>php artisan route:list</code>) and test parent-child active states on desktop &amp; mobile.',
    'pages.operasional.panduan-tambah-menu.item_4' => 'Leaf menu is automatically active when <code>request()->routeIs($route . \'*\')</code> evaluates to true.',
    'pages.operasional.panduan-tambah-menu.item_5' => 'Parent menu automatically receives <code>active</code>, <code>here</code>, and <code>show</code> classes recursively if at least one child below it is active.',
    'pages.operasional.panduan-tambah-menu.item_6' => 'In dropdown mode, child active state still evaluates route wildcards to open the flyout.',
    'pages.operasional.panduan-tambah-menu.item_7' => '<strong>Menu Not Appearing:</strong> Check config file registration in <code>_menu.blade.php</code> and verify PHP array syntax.',
    'pages.operasional.panduan-tambah-menu.item_8' => '<strong>Title Not Translated:</strong> Check normalized <code>menu.*</code> key name and verify it exists in <code>lang/en/menu.php</code> and <code>lang/id/menu.php</code>.',
    'pages.operasional.panduan-tambah-menu.item_9' => '<strong>Parent Not Auto-Opening:</strong> Check child route name match and ensure wildcard <code>routeIs</code> covers all sub-routes.',
    'pages.operasional.panduan-tambah-menu.item_10' => '<strong>Icon Broken / Blank:</strong> Ensure Keenicons class is valid and <code>paths</code> attribute count matches the duotone icon span count.',
    'pages.operasional.panduan-tambah-menu.item_11' => '<strong>Zero Core Layout Edit Rule Mandatory:</strong> Modifying core partials (<code>_menu-item.blade.php</code>) or database seeders just to add static menu items is strictly forbidden.',
    'pages.operasional.panduan-tambah-menu.item_12' => '<strong>Bilingual Parity Rule Mandatory:</strong> Every new menu item must be registered in <code>lang/en/menu.php</code> and <code>lang/id/menu.php</code>.',
    'pages.operasional.panduan-tambah-menu.item_13' => '<strong>Mobile Drawer Test Rule Mandatory:</strong> Testing new menus must be performed on desktop (hover/accordion) and mobile (click drawer).',
    'pages.operasional.panduan-tambah-menu.item_14' => '<strong>Route Validation Rule Mandatory:</strong> Ensure target route is registered and active before submitting a Pull Request.',
    'pages.operasional.panduan-tambah-menu.item_15' => '<strong>Sidebar/Header Config Modularization:</strong> Static menu structures are split per domain in <code>config/sidebar/_sidebar_&lt;category&gt;.php</code> (dashboard, pages, apps, layouts, helps).',
    'pages.operasional.panduan-tambah-menu.item_16' => '<strong>Database Menu Seeder Modularization:</strong> Dynamic database/permission menus have seeders split per category in <code>config/menu_seeder/&lt;category&gt;_seeder.php</code> and seeded via <code>php artisan db:seed --class=MenuSeeder</code>.',
    'pages.operasional.panduan-tambah-menu.item_17' => '<strong>Core Seeder Preservation:</strong> Never modify core seeder files directly. Create separate seeders for new domain modules.',
    'pages.operasional.panduan-tambah-menu.item_18' => '<strong>Use route (Internal Recommendation):</strong> Use <code>\'route\' =&gt; \'name.route\'</code> for all internal Laravel page links. Advantages: safe from URL path refactoring, supports automatic active state <code>request()-&gt;routeIs(...)</code>, and route cache friendly.',
    'pages.operasional.panduan-tambah-menu.item_19' => '<strong>Use href (External/Anchor Links):</strong> Use <code>\'href\' =&gt; \'https://...\'</code> only for external URLs, page section anchor IDs (<code>#section</code>), or un-named static URLs.',
    'pages.operasional.panduan-tambah-menu.item_20' => '<strong>External Link Security:</strong> Any external <code>href</code> must include <code>\'target\' =&gt; \'_blank\'</code> for security (reverse tabnabbing prevention) and user convenience.',
    'pages.operasional.panduan-tambah-menu.item_21' => '<strong>Status Badge (badge):</strong> Displays a color badge next to the menu title, e.g. <code>\'badge\' =&gt; [\'text\' =&gt; \'New\', \'class\' =&gt; \'badge-light-success\']</code>.',
    'pages.operasional.panduan-tambah-menu.item_22' => '<strong>Custom Duotone Icon (icon):</strong> Specifies Keenicons duotone icon classes and path count, e.g. <code>\'icon\' =&gt; [\'element\' =&gt; \'ki-duotone ki-element-11\', \'paths\' =&gt; 4]</code>.',
    'pages.operasional.panduan-tambah-menu.item_23' => '<strong>Flyout Submenu Mode (dropdown):</strong> Set <code>\'dropdown\' =&gt; true</code> on parent node to change submenu from accordion to flyout popup.',
    'pages.operasional.panduan-tambah-menu.item_24' => '<strong>New Tab Target (target):</strong> Set <code>\'target\' =&gt; \'_blank\'</code> to open link in a new browser tab.',
    'pages.operasional.panduan-tambah-menu.item_25' => '<strong>Dot Indicator (bullet):</strong> Set <code>\'bullet\' =&gt; true</code> on leaf item to show a bullet dot next to the text.',
    'pages.operasional.panduan-tambah-menu.item_26' => '<strong>Show More/Less Feature (menus_dashboard_collapsed):</strong> Dedicated array for dashboard menus to hide extra items that expand interactively.',
    'pages.operasional.panduan-tambah-menu.note_1' => 'Minimum leaf item attributes: title + route or title + href. Parent nodes must include a children[] array.',
    'pages.operasional.panduan-tambah-menu.note_2' => 'Run php artisan config:clear and php artisan view:clear if menu updates do not immediately reflect in the browser.',

    // Pages - Operasional Konvensi Penamaan
    'pages.operasional.konvensi-penamaan.hero_title' => 'Operational Guide: Naming Conventions',
    'pages.operasional.konvensi-penamaan.hero_lead' => 'Standard naming convention rules for Blade files, Controllers, Models, Form Requests, Routes, Database Schemas, Translation Keys, and JavaScript helpers in the application architecture.',
    'pages.operasional.konvensi-penamaan.lead' => 'Step-by-step practical guide for file and system entity naming rules to maintain codebase consistency across developers.',
    'pages.operasional.konvensi-penamaan.chip_1' => 'kebab-case for Blade & Route',
    'pages.operasional.konvensi-penamaan.chip_2' => 'PascalCase for Controller & Model',
    'pages.operasional.konvensi-penamaan.chip_3' => 'snake_case for DB & i18n',
    'pages.operasional.konvensi-penamaan.chip_4' => 'camelCase for JS & Methods',
    'pages.operasional.konvensi-penamaan.heading_1' => 'Blade Views, Partials & Sub-Tabs Conventions (kebab-case)',
    'pages.operasional.konvensi-penamaan.heading_2' => 'Controllers, Models & Form Requests Conventions (PascalCase Mirror)',
    'pages.operasional.konvensi-penamaan.heading_3' => 'Route Names & URL Paths Conventions (kebab-case)',
    'pages.operasional.konvensi-penamaan.heading_4' => 'Database Schemas & Migrations Conventions (snake_case)',
    'pages.operasional.konvensi-penamaan.heading_5' => 'i18n Translation Keys Conventions (snake_case)',
    'pages.operasional.konvensi-penamaan.heading_6' => 'Controller Methods & JS Helpers Conventions (camelCase / PascalCase)',
    'pages.operasional.konvensi-penamaan.heading_7' => 'Codebase Naming Conventions Summary Matrix',
    'pages.operasional.konvensi-penamaan.heading_8' => 'Naming Verification & Operational Checklist',
    'pages.operasional.konvensi-penamaan.item_1' => '<strong>Main Blade View:</strong> Blade file names must use <code>kebab-case</code> inside feature subfolders (e.g., <code>resources/views/pages/appsupport/app-profil.blade.php</code>).',
    'pages.operasional.konvensi-penamaan.item_2' => '<strong>CRUD Form Partial:</strong> Modal form partial files must be placed in a <code>partials/</code> subfolder with a <code>-form.blade.php</code> suffix (e.g., <code>partials/app-profil-form.blade.php</code>).',
    'pages.operasional.konvensi-penamaan.item_3' => '<strong>Sub-Tab Partial:</strong> Sub-tab partial files must be placed in a <code>tabs/</code> subfolder and prefixed with an underscore <code>_</code> (e.g., <code>tabs/_keamanan.blade.php</code>).',
    'pages.operasional.konvensi-penamaan.item_4' => '<strong>Controller Mirroring:</strong> Controller namespaces must be <code>PascalCase</code> (StudlyCaps) mirroring the Blade folder structure (e.g., <code>App\\Http\\Controllers\\AppSupport\\AppProfilController.php</code>).',
    'pages.operasional.konvensi-penamaan.item_5' => '<strong>Model Mirroring:</strong> Models must be singular <code>PascalCase</code> in matching subfolders (e.g., <code>App\\Models\\AppSupport\\AppProfil.php</code>).',
    'pages.operasional.konvensi-penamaan.item_6' => '<strong>Form Request Validation:</strong> Form Request files must share the matching namespace with a <code>Request</code> suffix (e.g., <code>App\\Http\\Requests\\AppSupport\\AppProfilRequest.php</code>).',
    'pages.operasional.konvensi-penamaan.item_7' => '<strong>Route Name Format:</strong> Dot-separated <code>kebab-case</code> reflecting folder hierarchy (e.g., <code>help.pemrograman.operasional.konvensi-penamaan</code> or <code>appsupport.app-profil</code>).',
    'pages.operasional.konvensi-penamaan.item_8' => '<strong>Database Table Name:</strong> Plural <code>snake_case</code> (e.g., <code>users</code>, <code>app_profiles</code>, <code>menu_seeders</code>).',
    'pages.operasional.konvensi-penamaan.item_9' => '<strong>Primary & Foreign Keys:</strong> Primary key is <code>id</code>; foreign keys use singular <code>snake_case_id</code> (e.g., <code>user_id</code>, <code>role_id</code>).',
    'pages.operasional.konvensi-penamaan.item_10' => '<strong>Timestamp & State Columns:</strong> Use <code>snake_case</code> (e.g., <code>created_at</code>, <code>updated_at</code>, <code>is_active</code>, <code>status_code</code>).',
    'pages.operasional.konvensi-penamaan.item_11' => '<strong>Menu Translation Key:</strong> Normalized menu keys use <code>menu.snake_case</code> in <code>lang/*/menu.php</code> (e.g., <code>\'panduan_tambah_halaman\' =&gt; \'Add Page\'</code>).',
    'pages.operasional.konvensi-penamaan.item_12' => '<strong>Page Translation Key:</strong> Page keys use dot-hierarchical <code>snake_case</code> in <code>lang/*/help.php</code> (e.g., <code>pages.operasional.konvensi-penamaan.hero_title</code>).',
    'pages.operasional.konvensi-penamaan.item_13' => '<strong>Controller Methods (camelCase):</strong> Standard Laravel CRUD action methods (e.g., <code>index()</code>, <code>store()</code>, <code>update()</code>, <code>destroy()</code>, <code>getDatatable()</code>).',
    'pages.operasional.konvensi-penamaan.item_14' => '<strong>JS Helper & Methods:</strong> JS Helper objects use <code>PascalCase</code> (<code>SwalHelper</code>); methods use <code>camelCase</code> (<code>SwalHelper.success()</code>, <code>SwalHelper.validationError(xhr)</code>).',
    'pages.operasional.konvensi-penamaan.step_1' => '1. Define module subfolder and feature name (e.g., module <code>appsupport</code>, feature <code>app-profil</code>).',
    'pages.operasional.konvensi-penamaan.step_2' => '2. Create <code>kebab-case</code> Blade view at <code>resources/views/pages/appsupport/app-profil.blade.php</code>.',
    'pages.operasional.konvensi-penamaan.step_3' => '3. Create mirrored <code>PascalCase</code> Controller at <code>App\\Http\\Controllers\\AppSupport\\AppProfilController.php</code>.',
    'pages.operasional.konvensi-penamaan.step_4' => '4. Verify all file names &amp; namespaces by running <code>php artisan route:list</code> and <code>php artisan view:clear</code>.',
    'pages.operasional.konvensi-penamaan.note_1' => 'Maintain strict consistency! Never mix snake_case or camelCase into Blade file names or Controller class names.',

    // Pages - Operasional Workflow Developer Harian
    'pages.operasional.workflow-developer-harian.hero_title' => 'Operational Guide: Daily Developer Workflow',
    'pages.operasional.workflow-developer-harian.hero_lead' => 'Standard daily developer workflow guide from local environment setup, feature development, bilingual navigation registration, cache clearing, to pre-commit verification checklists.',
    'pages.operasional.workflow-developer-harian.lead' => 'Daily workflow guide for developer teams to maintain efficiency, codebase consistency, and application release quality.',
    'pages.operasional.workflow-developer-harian.chip_1' => 'Env Setup & Asset Build',
    'pages.operasional.workflow-developer-harian.chip_2' => 'Mirror Code Structure',
    'pages.operasional.workflow-developer-harian.chip_3' => 'Bilingual i18n Parity',
    'pages.operasional.workflow-developer-harian.chip_4' => 'Pre-commit Verification',
    'pages.operasional.workflow-developer-harian.heading_1' => 'Step 1: Environment Setup & Initial Loading (Daily Start)',
    'pages.operasional.workflow-developer-harian.heading_2' => 'Step 2: Feature Development & Mirror Structure',
    'pages.operasional.workflow-developer-harian.heading_3' => 'Step 3: Navigation Registration & i18n Translation',
    'pages.operasional.workflow-developer-harian.heading_4' => 'Step 4: Cache Clearing CLI Commands & Debugging',
    'pages.operasional.workflow-developer-harian.heading_5' => 'Step 5: UI Standardization & JS Helpers (SwalHelper & Tooltips)',
    'pages.operasional.workflow-developer-harian.heading_6' => 'Step 6: Git Branching, Commit & PR Governance',
    'pages.operasional.workflow-developer-harian.heading_7' => 'Pre-Commit & Pre-Release Verification Checklist',
    'pages.operasional.workflow-developer-harian.item_1' => '<strong>Repository Sync:</strong> Run <code>git pull origin main</code> to ensure local code is up-to-date with the main branch.',
    'pages.operasional.workflow-developer-harian.item_2' => '<strong>Asset Build:</strong> Run <code>npm run dev</code> for frontend CSS/JS hot-reloading compilation.',
    'pages.operasional.workflow-developer-harian.item_3' => '<strong>Database Migration:</strong> Run <code>php artisan migrate</code> if migration files were updated.',
    'pages.operasional.workflow-developer-harian.item_4' => '<strong>Create Blade View:</strong> Create <code>kebab-case</code> Blade files at <code>resources/views/pages/&lt;folder&gt;/&lt;page&gt;.blade.php</code>.',
    'pages.operasional.workflow-developer-harian.item_5' => '<strong>Create Controller &amp; Model (Mirror):</strong> Create Controller &amp; Model in matching subfolders (<code>App\\Http\\Controllers\\&lt;Folder&gt;\\&lt;Page&gt;Controller.php</code>).',
    'pages.operasional.workflow-developer-harian.item_6' => '<strong>Extract CRUD Form Partial:</strong> Separate modal HTML into <code>partials/&lt;feature&gt;-form.blade.php</code> and create Form Request validation.',
    'pages.operasional.workflow-developer-harian.item_7' => '<strong>Navigation Menu Config:</strong> Add menu items to <code>config/sidebar/_sidebar_*.php</code>.',
    'pages.operasional.workflow-developer-harian.item_8' => '<strong>Bilingual Translation (EN/ID):</strong> Must register title keys in both <code>lang/en/menu.php</code> and <code>lang/id/menu.php</code>.',
    'pages.operasional.workflow-developer-harian.item_9' => '<strong>Optimize &amp; Clear Cache:</strong> Run <code>php artisan optimize:clear</code> when creating new routes or views.',
    'pages.operasional.workflow-developer-harian.item_10' => '<strong>Active Route Inspection:</strong> Run <code>php artisan route:list --name=&lt;route-name&gt;</code> to verify URL registration.',
    'pages.operasional.workflow-developer-harian.item_11' => '<strong>Use Global SwalHelper:</strong> Use <code>SwalHelper.success()</code>, <code>SwalHelper.error()</code>, and <code>SwalHelper.validationError(xhr)</code> for JS notifications.',
    'pages.operasional.workflow-developer-harian.item_12' => '<strong>Top Tooltip Wrapper:</strong> All <code>btn-icon</code> buttons must have top tooltips and <code>&lt;span&gt;</code> wrappers on modal triggers.',
    'pages.operasional.workflow-developer-harian.item_13' => '<strong>Create Feature Branch:</strong> Use the naming format <code>git checkout -b feature/feature-name</code>.',
    'pages.operasional.workflow-developer-harian.item_14' => '<strong>PHP Syntax Check:</strong> Run <code>php -l</code> on modified PHP files before committing.',
    'pages.operasional.workflow-developer-harian.step_1' => '1. Pull latest code updates (git pull origin main).',
    'pages.operasional.workflow-developer-harian.step_2' => '2. Create a new feature branch &amp; develop code following naming conventions.',
    'pages.operasional.workflow-developer-harian.step_3' => '3. Execute cache clearing &amp; test UI rendering (desktop &amp; mobile).',
    'pages.operasional.workflow-developer-harian.step_4' => '4. Commit with descriptive messages &amp; submit a Pull Request to the main repo.',
    'pages.operasional.workflow-developer-harian.note_1' => 'Direct commits to the main branch are strictly forbidden! All changes must go through a Feature Branch and Pull Request review.',

    // Pages - Operasional Checklist QA Smoke Test
    'pages.operasional.checklist-qa-smoke-test.hero_title' => 'Operational Guide: Pre-Release QA & Smoke Test Checklist',
    'pages.operasional.checklist-qa-smoke-test.hero_lead' => 'Mandatory pre-release operational QA checklist to verify navigation, table responsiveness, SwalHelper CRUD, top tooltips, and 100% bilingual parity.',
    'pages.operasional.checklist-qa-smoke-test.lead' => 'Minimum testing checklist guide that must be satisfied before features are submitted to Pull Requests or production releases.',
    'pages.operasional.checklist-qa-smoke-test.chip_1' => 'Navigation & Route Test',
    'pages.operasional.checklist-qa-smoke-test.chip_2' => 'Responsive Table Check',
    'pages.operasional.checklist-qa-smoke-test.chip_3' => 'SwalHelper & Tooltips',
    'pages.operasional.checklist-qa-smoke-test.chip_4' => 'Bilingual Parity Verification',
    'pages.operasional.checklist-qa-smoke-test.heading_1' => 'Checklist 1: Navigation & Active State Menu Testing',
    'pages.operasional.checklist-qa-smoke-test.heading_2' => 'Checklist 2: Table Responsiveness & Layout Testing',
    'pages.operasional.checklist-qa-smoke-test.heading_3' => 'Checklist 3: Operational CRUD & SwalHelper Testing',
    'pages.operasional.checklist-qa-smoke-test.heading_4' => 'Checklist 4: Top Tooltips & Modal Trigger Wrapper Testing',
    'pages.operasional.checklist-qa-smoke-test.heading_5' => 'Checklist 5: Multi-Language Parity Testing (EN & ID)',
    'pages.operasional.checklist-qa-smoke-test.heading_6' => 'Checklist 6: CLI Commands Verification & Cache Clearing',
    'pages.operasional.checklist-qa-smoke-test.heading_7' => 'QA Gatekeeper & Release Approval Standards',
    'pages.operasional.checklist-qa-smoke-test.item_1' => '<strong>URL Access &amp; Route:</strong> All new pages can be opened without HTTP 404, 500 errors, or layout breakage.',
    'pages.operasional.checklist-qa-smoke-test.item_2' => '<strong>Active Highlight:</strong> Sidebar and header menus precisely receive <code>active</code> / <code>here</code> highlights based on current route.',
    'pages.operasional.checklist-qa-smoke-test.item_3' => '<strong>Mobile Drawer:</strong> Navigation menus open and close smoothly on mobile screens via the mobile drawer.',
    'pages.operasional.checklist-qa-smoke-test.item_4' => '<strong>Responsive Wrapper:</strong> All data tables are wrapped in <code>&lt;div class="table-responsive"&gt;</code> ensuring horizontal scrolling works on mobile/tablets.',
    'pages.operasional.checklist-qa-smoke-test.item_5' => '<strong>Column Width Preservation:</strong> <code>&lt;th&gt;</code> elements use Metronic\'s native minimum width classes (<code>min-w-200px</code>, <code>min-w-150px</code>).',
    'pages.operasional.checklist-qa-smoke-test.item_6' => '<strong>Layout Partial Cleanliness:</strong> Tab partials do not contain <code>@@endsection</code>, <code>@@extends</code>, or main <code>&lt;/div&gt;</code> closing tags that cut off the footer.',
    'pages.operasional.checklist-qa-smoke-test.item_7' => '<strong>CRUD Success Notification:</strong> Data creation &amp; updates trigger <code>SwalHelper.success()</code> alerts.',
    'pages.operasional.checklist-qa-smoke-test.item_8' => '<strong>Delete Confirmation:</strong> Data deletion triggers the <code>SwalHelper.confirmDelete()</code> dialog before sending the request.',
    'pages.operasional.checklist-qa-smoke-test.item_9' => '<strong>422 XHR Error Handling:</strong> AJAX validation failures display error message lists via <code>SwalHelper.validationError(xhr)</code>.',
    'pages.operasional.checklist-qa-smoke-test.item_10' => '<strong>Icon-only Tooltips:</strong> All <code>btn-icon</code> buttons have <code>data-bs-toggle="tooltip" data-bs-placement="top" title="..."</code> attributes.',
    'pages.operasional.checklist-qa-smoke-test.item_11' => '<strong>Modal Trigger Wrapper:</strong> Modal trigger buttons are wrapped in <code>&lt;span data-bs-toggle="tooltip" ...&gt;</code> to prevent attribute collision.',
    'pages.operasional.checklist-qa-smoke-test.item_12' => '<strong>100% English (en):</strong> When switching to the <code>en</code> locale, no Indonesian text remains in menus or page content.',
    'pages.operasional.checklist-qa-smoke-test.item_13' => '<strong>100% Indonesian (id):</strong> When switching to the <code>id</code> locale, all titles, buttons, and instructions display cleanly in Indonesian.',
    'pages.operasional.checklist-qa-smoke-test.item_14' => '<strong>View &amp; Config Cache Clear:</strong> Run <code>php artisan optimize:clear</code> and re-test the application from a clean state.',
    'pages.operasional.checklist-qa-smoke-test.step_1' => '1. Run navigation &amp; layout responsiveness tests (desktop &amp; mobile).',
    'pages.operasional.checklist-qa-smoke-test.step_2' => '2. Test CRUD flow, SwalHelper, 422 XHR validation, and delete confirmations.',
    'pages.operasional.checklist-qa-smoke-test.step_3' => '3. Test language switching (en &amp; id) to guarantee 100% bilingual parity.',
    'pages.operasional.checklist-qa-smoke-test.step_4' => '4. Clear cache using php artisan optimize:clear before approving release.',
    'pages.operasional.checklist-qa-smoke-test.note_1' => 'Features are strictly forbidden to release if any single checklist item fails! All 5 testing categories must evaluate to PASS.',

    // Pages - Operasional Playbook Incident Response
    'pages.operasional.playbook-incident-response.hero_title' => 'Operational Guide: Incident Response Playbook',
    'pages.operasional.playbook-incident-response.hero_lead' => 'Standard operating procedure for production incident response (Sev-1 to Sev-4), war-room role matrix, 15-minute rapid mitigation workflow, stakeholder communication templates, emergency CLI commands, and post-mortem analysis.',
    'pages.operasional.playbook-incident-response.lead' => 'Tactical operational guide for engineering teams to respond to and mitigate production incidents in a structured and measurable manner.',
    'pages.operasional.playbook-incident-response.chip_1' => 'Sev-1 to Sev-4 Triage',
    'pages.operasional.playbook-incident-response.chip_2' => 'War-Room Role Matrix',
    'pages.operasional.playbook-incident-response.chip_3' => '15-Min Rapid Mitigation',
    'pages.operasional.playbook-incident-response.chip_4' => 'Blameless Post-Mortem',
    'pages.operasional.playbook-incident-response.heading_1' => 'Incident Team Roles & Responsibilities (War-Room Roles)',
    'pages.operasional.playbook-incident-response.heading_2' => 'Incident Severity Level Matrix',
    'pages.operasional.playbook-incident-response.heading_3' => '15-Minute Rapid Response Timeline for Sev-1 (Critical Playbook)',
    'pages.operasional.playbook-incident-response.heading_4' => '15-Minute Rapid Response Timeline for Sev-2 (Major Playbook)',
    'pages.operasional.playbook-incident-response.heading_5' => 'Sev-3 & Sev-4 Incident Response Procedures (Medium/Low Playbook)',
    'pages.operasional.playbook-incident-response.heading_6' => 'Stakeholder Broadcast Communication Templates',
    'pages.operasional.playbook-incident-response.heading_7' => 'Emergency CLI Mitigation Commands (Emergency Operations)',
    'pages.operasional.playbook-incident-response.heading_8' => 'Post-Mortem Workflow & Prevention Actions (Blameless Review)',
    'pages.operasional.playbook-incident-response.item_1' => '<strong>Incident Commander (IC):</strong> Leads decisions, establishes severity status, and determines priority mitigation actions.',
    'pages.operasional.playbook-incident-response.item_2' => '<strong>Ops Lead (Backend/Infra):</strong> Executes emergency technical actions (rollback releases, traffic isolation, worker restarts, feature flags).',
    'pages.operasional.playbook-incident-response.item_3' => '<strong>Comms Lead:</strong> Sends regular official status updates to internal stakeholders and users.',
    'pages.operasional.playbook-incident-response.item_4' => '<strong>Scribe:</strong> Records incident timeline chronology, key decisions, error logs, and supporting evidence.',
    'pages.operasional.playbook-incident-response.item_5' => '<strong>Sev-1 (Critical):</strong> System total outage, data breach, or core transaction complete failure. Requires full war-room &amp; response &lt; 5 mins.',
    'pages.operasional.playbook-incident-response.item_6' => '<strong>Sev-2 (Major):</strong> Core feature impaired but partial workaround available. Response &lt; 15 mins.',
    'pages.operasional.playbook-incident-response.item_7' => '<strong>Sev-3 (Medium):</strong> Non-critical feature bugs or minor performance degradation. Response &lt; 2 hours.',
    'pages.operasional.playbook-incident-response.item_8' => '<strong>Sev-4 (Low):</strong> Cosmetic UI glitch or minor error without business impact. Scheduled in sprint backlog.',
    'pages.operasional.playbook-incident-response.item_9' => '<strong>Standard Update Broadcast:</strong> [STATUS: INVESTIGATING/MITIGATED] Sev-X Incident [Module Name]. Impact: [User Impact Details]. Action: [Ongoing Action]. Next Update ETA: [Time].',
    'pages.operasional.playbook-incident-response.item_10' => '<strong>Root Cause Analysis Method (5-Whys):</strong> Uncover core root cause without pointing fingers (blameless culture).',
    'pages.operasional.playbook-incident-response.item_11' => '<strong>Action Item Logging:</strong> Assign owners and deadlines for permanent post-incident fixes.',
    'pages.operasional.playbook-incident-response.step_1' => '1. Detection &amp; Severity Declaration by Incident Commander (0-5 mins).',
    'pages.operasional.playbook-incident-response.step_2' => '2. War-Room Formation &amp; Fastest Mitigation Execution by Ops Lead (5-10 mins).',
    'pages.operasional.playbook-incident-response.step_3' => '3. User Impact Verification &amp; Official Broadcast Update #1 by Comms Lead (10-15 mins).',
    'pages.operasional.playbook-incident-response.step_4' => '4. Blameless Post-Mortem Execution &amp; Action Items Assignment (within max 48 hours post-incident).',
    'pages.operasional.playbook-incident-response.note_1' => 'The top priority during an active incident is to restore service (fastest mitigation), NOT to search for the root cause in the middle of an outage.',
];






